INSERT INTO public.questions VALUES ('fbc8a268-7202-4fd0-be25-930391cee8e8', '4e775b7a-3a94-481f-842d-1f442a8aeb3e', 'matrix', 'Questions 11–15', '', '<p>Label the map below. </p>
<p>Choose the correct letter,<strong> A-H</strong>, next to questions 11-15.</p>
<p><img src="data:image/png;base64," width="587" height="549"></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "seating area", "correctCategoryLetter": "C"}, {"itemText": "cushions", "correctCategoryLetter": "F"}, {"itemText": "computer bench", "correctCategoryLetter": "D"}, {"itemText": "café bar", "correctCategoryLetter": "A"}, {"itemText": "newspapers", "correctCategoryLetter": "H"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 2: BIBLIOSTACK BOOKSHOP</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Manager:</strong> Good morning everyone and a big welcome to Bibliostack. Firstly, I''ll explain the plan of the store to you. The building is on 7 floors and is circular, as you can see, and we''re here on the ground floor in its entrance hall.</p>\n<p data-path-to-node=\"4\">Right in the center of this floor, but behind the bookshelf—so you can''t see it very well from here—is our <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"107\">(Q11) main seating area (G)</strong></span>, where people are encouraged to sit and read for as long as they like. But they''re under no pressure to buy what they''re reading; that''s not how we operate.</p>\n<p data-path-to-node=\"5\">And if you look to your immediate left, past the first double row of shelves, you''ll see piles of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"98\">(Q12) coloured cushions (B)</strong></span> in front of the window there. We provide those so that people can sit wherever they want. Lots of people like to sit close to the bookshelves, and if they want to sit on the floor there, we want them to be as comfortable as possible.</p>\n<p data-path-to-node=\"6\">On your right, between the two larger bookshelves, you''ll see the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"66\">(Q13) computer bench (C)</strong></span> where our visitors can search through our entire catalogue. We pride ourselves in being the largest bookshop in the country, so our sales assistants can''t possibly know all the available titles.</p>\n<p data-path-to-node=\"7\">Although the room in front of you is dominated by the bookshelves, at the far end, just in front of the lift, you''ll see that we provide a small <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"145\">(Q14) cafe bar (A)</strong></span> here too.</p>\n<p data-path-to-node=\"8\">And just to your right, there''s a door to the cloakroom where people can leave their coats. Then after that, there''s a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"119\">(Q15) stand (E)</strong></span> where we keep a selection of local and national <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"183\">newspapers</strong></span>. Customers are welcome to browse through them, and we also have some for sale. We really want people to feel as though they''re browsing through books in the comfort of their own home.</p>\n<hr data-path-to-node=\"9\">\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">STORE OPERATIONS (Questions 16–20)</strong></h3>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Manager:</strong> Right now, I suggest we walk slowly up through the building and I''ll give you more information as we go. We''re open 12 hours a day. We don''t mind if people spend the whole day here but leave without buying anything. Of course we hope they''ll buy something, but <strong data-path-to-node=\"11\" data-index-in-node=\"270\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q16) our purpose is to draw people in, to provide the kind of environment which makes them want to stay and read</span>.</strong> Look at how busy each floor is, but how quiet. You may be wondering whether there are any children in the building. We debated about locating children''s books on the ground floor or halfway up the building, like the third or fourth floor, but in the end, <strong data-path-to-node=\"11\" data-index-in-node=\"640\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q17) we decided to put them on the very top level</span>.</strong> And I can assure you, it''s not the least bit quiet up there!</p>\n<p data-path-to-node=\"12\">Of course, many parents would prefer to spend time on other floors and so we provide a supervised area for children under 2 in the basement. So parents can wander around the shop for a few hours and not worry. But they do have to pay for this service because although we thought about using some of our own assistants, <strong data-path-to-node=\"12\" data-index-in-node=\"319\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q18) we decided to employ qualified nursery staff for parents'' complete peace of mind</span>.</strong> Now we''re just passing the fiction section, and you''ve probably noticed a small crowd of people beginning to gather. That''s because a well-known author is going to read from her latest novel. We try to hold events like this at least once or twice a week, and as you can imagine they''re very popular. We don''t make a charge for people to attend, but <strong data-path-to-node=\"12\" data-index-in-node=\"756\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q19) we obviously hope that some of them will want to purchase the book after listening to part of it being read aloud</span>.</strong> Other events which are proving to be very popular are our workshops. Last week we held a poetry workshop and people came along with poems that they''d written. One of the country''s best-known poets ran the workshop and <strong data-path-to-node=\"12\" data-index-in-node=\"1095\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q20) the participants read their poems aloud to him</span>.</strong> He was kind and encouraging and many people felt inspired by his advice.</p>\n<p data-path-to-node=\"13\">It''s extremely difficult to earn your living as a professional poet, and even published poets have other jobs. Now we''re going to take a look at our section on audio books...</p>"}]', 0);
INSERT INTO public.questions VALUES ('ad45e233-ddcd-4b3b-b133-16b3e570b485', '31dd67b8-8a3b-4d3e-ac3d-2a972c889c4a', 'fillup', 'Questions 1-10', '<p><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Complete the notes below.</span></p>
<p><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</span><strong><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;"> </span></strong></p>
<p><strong><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Wedding arrangements – Clarence House Hotel</span></strong></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Available date: 1st June</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">The Oxford Suite has:</span></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l2 level1 lfo1; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">a dining room with a good view of the {city}</span></span></li>
</ul>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l1 level1 lfo2; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">a private garden for {photos} </span></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">and for the wedding ceremony</span></li>
</ul>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l5 level1 lfo3; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">an area suitable for dancing</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">The wedding package includes:</span></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l3 level1 lfo4; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">use of the Oxford Suite</span></li>
</ul>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l4 level1 lfo5; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">a three-course meal</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">+ room arranged with {round} </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">tables</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">+ table {decorations} </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">included</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">+ white tablecloths and chairs</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">+ personalised printed {menu}</span></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l0 level1 lfo6; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">a late-evening buffet with a choice of {sandwiches} </span></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">and hot drinks</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Music: hotel will organise a band (not included in price)</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Total cost of package: £ {5995}</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Can also recommend a {cake} </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">supplier (new company)</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Wedding coordinator Sarah {Izard}</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Date arranged for visit: {15th October | 15 October| October 15| October 15th} </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">at 11.30 a.m</span></p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a telephone conversation between a hotel manager and a woman who is inquiring about wedding arrangements. First you have some time to look at questions 1 to five. Now listen carefully and answer questions 1 to five.</p>\n<p><strong>Hotel Manager:</strong> Hello, Clarence House.</p>\n<p><strong>Woman:</strong> Oh, hello. Um, I’m getting married next year, and I understand you’re licensed to hold weddings at the hotel.</p>\n<p><strong>Hotel Manager:</strong> Yes, we are. Can I ask what date you were thinking of?</p>\n<p><strong>Woman:</strong> Either the 1st or the 7th of June.</p>\n<p><strong>Hotel Manager:</strong> Right, let me see. Oh, I’m afraid we already have a booking for the 7th, but we still have availability on <strong>June the first</strong>.</p>\n<p><strong>Woman:</strong> That would be fine.</p>\n<p><strong>Hotel Manager:</strong> So, how many guests are you going to be inviting?</p>\n<p><strong>Woman:</strong> About 80.</p>\n<p><strong>Hotel Manager:</strong> So, for that number, we’d recommend the Oxford Suite. I don’t know if you’ve been to the hotel?</p>\n<p><strong>Woman:</strong> Yes, in fact, I went to a wedding there a few years ago and I was really impressed.</p>\n<p><strong>Hotel Manager:</strong> Very good. I think we’re in the Oxford Suite then. Um, the room where we were eating had big windows with really good views. You could see right across the <strong>(1) city</strong>.</p>\n<p><strong>Hotel Manager:</strong> That’s it. And you’d have exclusive access to the garden. It’ll be at its best in June, so we could have the <strong>(2) photos</strong> there.</p>\n<p><strong>Woman:</strong> Sure.</p>\n<p><strong>Hotel Manager:</strong> In fact, you can even have the ceremony there if you want. It makes a lovely background.</p>\n<p><strong>Woman:</strong> Oh, I hadn’t thought of that. Yes, that’s certainly an idea. And is there somewhere for dancing?</p>\n<p><strong>Hotel Manager:</strong> Yes, there’s plenty of space in the middle of the dining room.</p>\n<p><strong>Woman:</strong> Oh yeah, I remember now. So, just to give you an idea, would you like me to tell you about our special wedding package?</p>\n<p><strong>Hotel Manager:</strong> Sure. Right, so for 80 guests, you’d have the exclusive use of the Oxford Suite, as I said, and then a meal. So that would be in the dining room, and that would be a sit down meal with three courses.</p>\n<p><strong>Woman:</strong> And how’s the room arranged? I seem to remember you have <strong>(3) round</strong> tables?</p>\n<p><strong>Hotel Manager:</strong> That’s right. Most people prefer them to long tables. Long tables aren’t really very friendly, are they?</p>\n<p><strong>Woman:</strong> And what about <strong>(4) decorations</strong> on the tables?</p>\n<p><strong>Hotel Manager:</strong> They’re included in the package. And we have white linen tablecloths and white chair covers, and we also include an individually designed <strong>(5) menu</strong> specially printed for you. It’s something that people can take away to remember the occasion. That’s something we’ve just started doing this year.</p>\n<p><strong>Woman:</strong> Alright.</p>\n<p><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions 6 to ten. Now listen and answer questions 6 to ten.</p>\n<p><strong>Hotel Manager:</strong> And then towards the end of the evening, when everyone’s beginning to run out of energy, we bring in a buffet. Nothing too complicated, just a selection of <strong>(6) sandwiches</strong> together with tea or coffee. That’s always very popular.</p>\n<p><strong>Woman:</strong> Right. And we want some music. Is that included in the package?</p>\n<p><strong>Hotel Manager:</strong> No, but we could probably get you a DJ. Oh, we know of a very good band, if you’d prefer that.</p>\n<p><strong>Woman:</strong> Yes, that’d be better actually. Something to get everyone on their feet.</p>\n<p><strong>Hotel Manager:</strong> Good. So, apart from the music, you said that’s an all-inclusive package. So, how much does that package come to?</p>\n<p><strong>Hotel Manager:</strong> <strong>£5,995</strong>.</p>\n<p><strong>Woman:</strong> That’s a bit more than the package they quoted for me at the Stanley Hotel. Theirs was £4,500.</p>\n<p><strong>Hotel Manager:</strong> Yes, but I think if you look at what you’re getting for the money, you’ll find we’re the best value, and it is a big day after all.</p>\n<p><strong>Woman:</strong> Yes, you’re probably right. Oh, and I nearly forgot. I’m looking for someone who can make me a really special <strong>(8) cake</strong>. Can you suggest one?</p>\n<p><strong>Hotel Manager:</strong> Certainly. There’s a new company that we’ve started using. They’re very good. In fact, our wedding coordinator will be able to give you all sorts of advice. We can offer you a free consultation and a tour of the venue.</p>\n<p><strong>Woman:</strong> Yes, well I’d definitely be interested.</p>\n<p><strong>Hotel Manager:</strong> Right. Well, the coordinator’s name is Sarah <strong>(9) Izard</strong>. That’s I-Z-A-R-D. Now, when would you like to meet her? She’s available from 9 to 5 most weekdays, or later if that’s more convenient.</p>\n<p><strong>Woman:</strong> Uh, I’m free on October 12th in the morning sometime, or <strong>(10) October 15th</strong> that would be better, thanks. Should we say 11:30?</p>\n<p><strong>Hotel Manager:</strong> Fine. And can I just take your name and a contact number?</p>\n<p><strong>Woman:</strong> Sure. It’s Debbie…</p>\n<p><strong>Narrator:</strong> That is the end of part 1. You now have one minute to check your answers to part one.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('c72fa67c-3ea5-43c3-af03-15897c285d18', '4e775b7a-3a94-481f-842d-1f442a8aeb3e', 'radio', 'Questions 16–20', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "sell as many books as possible"}, {"option_text": "create an energetic environment"}, {"option_text": "attract people to remain in the store"}], "question": "bookshop aims to"}, {"correct": 1, "options": [{"option_text": "on the ground floor"}, {"option_text": "on the highest level"}, {"option_text": "midway up the building"}], "question": "children’s books can be found"}, {"correct": 2, "options": [{"option_text": "trains shop floor-staff to look after children"}, {"option_text": "has a free nursery for children"}, {"option_text": "offers professional childcare"}], "question": "in order to help parents relax in the store, Bibiliostack"}, {"correct": 0, "options": [{"option_text": "persuading people to buy books"}, {"option_text": "encouraging authors to get together"}, {"option_text": "bringing in extra money by charging"}], "question": " Bibiliostack holds regular book reading as a way of"}, {"correct": 2, "options": [{"option_text": "were encouraged to have their work published"}, {"option_text": "were considering becoming professional poets"}, {"option_text": "were willing to read their own work in public"}], "question": "The people who took part in Bibiliostack''s poetry workshop"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('a59ec3fc-c1d0-42b8-8264-f840f32f2130', 'c0508fac-8a07-40f8-b234-129015847c99', 'fillup', 'Questions 32-35', '<p>Complete the summary below</p>
<p>Choose<strong> NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 32-35 on your answer sheet.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong data-path-to-node="11" data-index-in-node="0">Persuasion techniques</strong></span></p>
<p>Shops use a variety of methods to make us do what they want. The area just inside the entrance of a supermarket is known as the {decompression zone}. Sometimes an employee will welcome you there, because it has been found that this results in a lower rate of {shoplifting}. Food is not always arranged in the most logical way. for example it would be better for us to buy {fruit} last, but this isn’t what we are encouraged to do. Smell used to attract customers, for example most stores have a {bakery} despite the fact that it isn’t a very efficient method of production.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">32. The area just inside the entrance of a supermarket is known as the {decompression zone}.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…there is a part of the shop immediately inside the doors, the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"86\">decompression zone</strong>, where people can slow down…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “immediately inside the doors” tương ứng với “just inside the entrance”. Tên gọi chuyên môn của khu vực này chính là <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"136\">decompression zone</strong>.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">33. …because it has been found that this results in a lower rate of {shoplifting}.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Whether or not they boost sales, a friendly face [greeters] is said to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"92\">minimize shoplifting</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Minimize” (giảm thiểu) tương ứng với “lower rate”. Việc có nhân viên chào đón (greeters) giúp hạn chế tình trạng trộm cắp trong cửa hàng (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"151\">shoplifting</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">34. …for example it would be better for us to buy {fruit} last, but this isn’t what we are encouraged to do.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">Fruit</strong> can be damaged so it <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"48\">should be bought at the end</strong>, not the beginning, of a shopping trip.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả lập luận rằng theo logic, trái cây (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"56\">fruit</strong>) nên được mua cuối cùng (at the end = last) để tránh bị dập nát, nhưng thực tế các siêu thị luôn để nó ở ngay đầu tiên.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">35. Smell used to attract customers, for example most stores have a {bakery} despite the fact that it isn’t a very efficient method of production.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Then there is the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"39\">bakery</strong>, which can be smelt before it is seen… even though central bakeries… are much <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"128\">more cost-effective</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Not very efficient” tương ứng với việc không “cost-effective” bằng các lò bánh trung tâm. Tuy nhiên, các cửa hàng vẫn duy trì tiệm bánh (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"150\">bakery</strong>) tại chỗ để dùng mùi hương thu hút khách.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b92944fc-cc1a-4931-9676-cee3fe11332b', 'c0508fac-8a07-40f8-b234-129015847c99', 'matrix', 'Questions 36-40', '', '<p>Match each statement with the correct person <strong>A-E</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "Research showed a promotion being wasted as shoppers already knew what they wanted.", "correctCategoryLetter": "A"}, {"itemText": "Offering people an extra, less attractive item can encourage them to choose.", "correctCategoryLetter": "C"}, {"itemText": "If shoppers realise they are being persuaded to buy something, they might react badly.", "correctCategoryLetter": "E"}, {"itemText": "People can often be persuaded to buy something if they are given a chance to try it first.", "correctCategoryLetter": "D"}, {"itemText": "For products shoppers know nothing about it is best to label them in a particular way.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Rajeev Sharma", "categoryLetter": "A"}, {"categoryText": "Cassie Mogilner", "categoryLetter": "B"}, {"categoryText": "Akshay Rao", "categoryLetter": "C"}, {"categoryText": "Scott Bearse", "categoryLetter": "D"}, {"categoryText": "Eric Spangenberg", "categoryLetter": "E"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">36. Research showed a promotion being wasted as shoppers already knew what they wanted. — {A} Rajeev Sharma</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…one company analysed people… buying carbonated drinks. Typically… the majority going straight to one brand, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"136\">ignoring any publicity</strong>. This shows their <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"177\">mind was made up</strong>… says <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"202\">Rajeev Sharma</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Ignoring any publicity” (lờ đi mọi quảng cáo) tương ứng với việc khuyến mãi bị lãng phí (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"102\">promotion being wasted</strong>). “Mind was made up” tương ứng với việc người mua đã biết rõ mình muốn gì (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"200\">already knew what they wanted</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. Offering people an extra, less attractive item can encourage them to choose. — {C} Akshay Rao</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“A third <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"29\">‘decoy’ item, which is not quite as good as the others</strong>, can make the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"98\">choice easier</strong>, according to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"126\">Akshay Rao</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Decoy item” (món đồ mồi) không tốt bằng những món khác chính là “extra, less attractive item”. Việc làm cho lựa chọn dễ dàng hơn tương ứng với “encourage them to choose”.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38. If shoppers realise they are being persuaded to buy something, they might react badly. — {E} Eric Spangenberg</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“But if they do <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"36\">realise psychological methods are being used</strong> to influence their choice, the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"112\">backlash can be so huge</strong> it can put someone off buying anything at all,’ says <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"189\">Eric Spangenberg</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Realise psychological methods” tương ứng với việc nhận ra mình bị thuyết phục (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"92\">realise they are being persuaded</strong>). “Backlash” (sự phản ứng dữ dội) chính là việc phản ứng tệ hại (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"190\">react badly</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">39. People can often be persuaded to buy something if they are given a chance to try it first. — {D} Scott Bearse</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“‘Getting customers to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"43\">taste food</strong> is one of best ways of getting them to buy,’ adds <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"104\">Mr Bearse</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Taste food” (nếm thử đồ ăn) chính là một cách để thử trước khi mua (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"81\">try it first</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">40. For products shoppers know nothing about it is best to label them in a particular way. — {B} Cassie Mogilner</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"13,0,0\" data-index-in-node=\"21\">Cassie Mogilner</strong>… found that consumers like <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"66\">unfamiliar products</strong> [= know nothing about] to be <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"115\">categorized</strong> [= label in a particular way]—even if there categories are meaningless.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Unfamiliar products” tương ứng với sản phẩm khách hàng không biết gì về nó. Việc “categorized” (phân loại) chính là cách dán nhãn/gọi tên theo một cách cụ thể.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('042008bc-4e5d-4c17-984e-cc63b4ef54c1', 'b51a7ed3-9516-492e-b796-304d93cfbf62', 'radio', 'Questions 21–26', NULL, '<p>Choose the correct letter, A, B or C.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "A. design development from 1800s "}, {"content": "B. design development and social advancement "}, {"content": "C. design development and art movement"}], "question": "Mona''s presentation topic is about "}, {"correct": 0, "options": [{"content": "A. She is afraid of her tutor’s response "}, {"content": "B. She wants to give a complete talk. "}, {"content": "C. She thinks it would be too simple."}], "question": "Mona doesn’t want to just talk about one topic because "}, {"correct": 2, "options": [{"content": "A. Very detailed "}, {"content": "B. Too old "}, {"content": "C. Too broad"}], "question": "What does Ted say about Mona’s topic? "}, {"correct": 1, "options": [{"content": "A. They have improved work efficiency. "}, {"content": "B. They have influenced traditional media. "}, {"content": "C. They have changed people’s sense of style."}], "question": "What is Mona’s viewpoint on computers? "}, {"correct": 0, "options": [{"content": "A. It’s important for architecture"}, {"content": "B. It saves a lot of effort"}, {"content": "C. He admires it in arts"}], "question": "Why does Ted think of “purism”?   "}, {"correct": 2, "options": [{"content": "A. meet one of his friends "}, {"content": "B. read more books "}, {"content": "C. visit a museum"}], "question": "What does Ted suggest Mona "}]', 'null', 'null', 'null', '[{"content": "<p>👇</p>\n<p>🎤 MONA’S PRESENTATION DISCUSSION<br />\nTED: You’ve looked at my presentation, haven’t you? What do you think of it?<br />\n🎧 Cậu xem bài thuyết trình của tớ rồi đúng không? Cậu thấy thế nào?</p>\n<p>MONA: Hey Mona, yes I have. Before giving you some advice, I have a question — why didn’t you write about the development of design and its influence or connection with social advancement or even art movement?<br />\n🎧 Có, mình có xem rồi. Trước khi góp ý, mình muốn hỏi — sao cậu không viết về sự phát triển của thiết kế và mối liên hệ với tiến bộ xã hội hoặc phong trào nghệ thuật?</p>\n<p>MONA: Actually, I just want to focus on the history of design, especially from the 1800s.<br />\n🎧 Thật ra, mình chỉ muốn tập trung vào lịch sử của thiết kế, đặc biệt từ thế kỷ 19 trở đi.<br />\n→ Answer 21: A – design development from 1800s</p>\n<p>TED: I see. Is it because you want to give a comprehensive talk?<br />\n🎧 À, là vì cậu muốn làm một bài thuyết trình bao quát hả?</p>\n<p>MONA: To be honest, I was worried about my teacher’s reaction. If I only talk about one area, she might think I’ve been lazy.<br />\n🎧 Thật ra mình sợ phản ứng của giáo viên. Nếu chỉ nói về một khía cạnh, cô có thể nghĩ mình lười biếng.<br />\n→ Answer 22: A – She is afraid of her tutor’s response</p>\n<p>TED: Even though it’s okay to talk about different aspects, I think the topic is too broad — it would be hard for the listeners to focus on any specific area.<br />\n🎧 Dù nói nhiều khía cạnh cũng được, nhưng mình nghĩ chủ đề của cậu quá rộng, người nghe khó tập trung được.<br />\n→ Answer 23: C – Too broad</p>\n<p>TED: You can use computer technology to assist you — maybe CAD or other software.<br />\n🎧 Cậu có thể dùng công nghệ máy tính hỗ trợ, như phần mềm CAD chẳng hạn.</p>\n<p>MONA: I’m not sure. Although computer technology can improve the visual effects of my presentation, I’d rather use the traditional way since I’m talking about the history of design. I guess traditional media is more affected by computers.<br />\n🎧 Mình không chắc đâu. Dù công nghệ máy tính giúp trình chiếu đẹp hơn, nhưng vì mình đang nói về lịch sử thiết kế, nên muốn giữ cách truyền thống. Mình nghĩ các phương tiện truyền thống mới là thứ bị ảnh hưởng nhiều bởi máy tính.<br />\n→ Answer 24: B – They have influenced traditional media</p>\n<p>TED: You mentioned purism, and you said it can save people’s effort. I don’t really agree with that. On the other hand, I do think it’s important to apply this concept in architecture — buildings should look simple and elegant.<br />\n🎧 Cậu có nhắc đến purism (chủ nghĩa thuần túy) và nói nó giúp tiết kiệm công sức. Mình không đồng ý, nhưng mình nghĩ nó rất quan trọng trong kiến trúc – các tòa nhà nên đơn giản và thanh nhã.<br />\n→ Answer 25: A – It’s important for architecture</p>\n<p>MONA: That’s a good point, Ted. What do you think I should do to further improve my talk?<br />\n🎧 Ý kiến hay đấy. Theo cậu mình nên làm gì để cải thiện bài nói?</p>\n<p>TED: I think you’ve read enough books. Why don’t you visit the Design Museum in the north of the city? One of my friends went there — he said it was worth it.<br />\n🎧 Mình nghĩ cậu đọc lý thuyết đủ rồi. Sao không ghé Bảo tàng Thiết kế ở phía bắc thành phố? Bạn mình mới đi và nói rất đáng xem đó.<br />\n→ Answer 26: C – visit a museum</p>\n<p>💡 TED’S TIPS FOR A SUCCESSFUL PRESENTATION (Questions 27–30)<br />\nMONA: How do you usually prepare for a presentation?<br />\n🎧 Cậu thường chuẩn bị bài thuyết trình như thế nào?</p>\n<p>TED: Step 1 — I always begin with an (Question 27) introduction, telling the audience what my topic is. It’s very important to grab attention.<br />\n🎧 Bước 1 — Mình luôn bắt đầu bằng phần mở đầu (introduction), giới thiệu chủ đề để thu hút sự chú ý của người nghe.<br />\n→ Answer 27: D – introduction</p>\n<p>TED: Step 2 — I would (Question 28) research deeper into the topic to give the audience something new.<br />\n🎧 Bước 2 — Mình sẽ nghiên cứu sâu hơn (research) về chủ đề để mang đến thông tin mới mẻ.<br />\n→ Answer 28: G – research</p>\n<p>TED: Step 3 — Put a (Question 29) statement under every picture, so the audience knows what the picture is about.<br />\n🎧 Bước 3 — Đặt một câu mô tả (statement) dưới mỗi hình để người xem hiểu rõ nội dung.<br />\n→ Answer 29: E – statement</p>\n<p>TED: Step 4 — Each slide should only contain one thought, and all thoughts should link together.<br />\n🎧 Bước 4 — Mỗi slide chỉ nên chứa một ý chính, các ý đó phải liên kết với nhau.</p>\n<p>TED: Step 5 — Finally, write some (Question 30) text handouts with key details for the audience to review later.<br />\n🎧 Bước 5 — Cuối cùng, chuẩn bị tờ ghi chú (text handouts) để người nghe xem lại sau buổi thuyết trình.<br />\n→ Answer 30: A – text handouts</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('51fecb0d-f11d-487b-b67e-fde2533f0ee9', '194a8ee8-b399-42ca-8ef6-3baf4dc1e427', 'radio', 'Questions 34–36', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A They are formed by strong winds blowing from one direction."}, {"content": "B They can move up to 100 metres in a twelve-month period"}, {"content": "C They develop in a recognisable shape."}, {"content": "D They make up about 20% of the world''s deserts."}], "question": "What are we told about linear dunes?"}, {"correct": 1, "options": [{"content": "A the long straight shape of the dunes"}, {"content": "B the particular composition of the dunes."}, {"content": "C the exceptionally heavy nature of the sand grains."}, {"content": "D the unusual strength of the wind in certain seasons."}], "question": "Bagnold discovered that movement in barchans was caused by"}, {"correct": 3, "options": [{"content": "A It starts small and then increases in size."}, {"content": "B It has an effect on its immediate surroundings."}, {"content": "C Its relations with desert organisms are quite developed"}, {"content": "D Its outline stays the same even after a period of movement"}], "question": "Why does Dr Douady compare a barchan dune to a living organism?"}]', 'null', 'null', 'null', '[{"content": "<p><strong>34. What are we told about linear dunes?</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: C. They develop in a recognisable shape.</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn B) &#8220;These form in a <strong>long curving wave</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> &#8220;Long curving wave&#8221; là một hình dạng có thể nhận biết được (recognisable shape). (A, B, D là sai hoặc không đúng với linear dunes).</p>\n</li>\n</ul>\n<p><strong>35. Bagnold discovered that movement in barchans was caused by</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: B. the particular composition of the dunes.</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn D) &#8220;&#8230;his answer hinges on the fact that dunes aren&#8217;t solid, but <strong>granular</strong>.&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Cơ chế di chuyển dựa trên việc đụn cát bao gồm các <strong>hạt cát</strong> (granular) riêng lẻ di chuyển theo chu kỳ, đây là <strong>thành phần/cấu tạo</strong> (composition) vật chất của đụn cát.</p>\n</li>\n</ul>\n<p><strong>36. Why does Dr Douady compare a barchan dune to a living organism?</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án: D. Its outline stays the same even after a period of movement.</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn E) &#8220;Interestingly, the dune can <strong>regulate its own shape, and maintain it as it moves</strong>&#8230; Even when two dunes collide, they quickly <strong>take on their distinctive shapes again</strong>.&#8221;</p>\n</li>\n<li>\n<p><strong>Giải thích:</strong> Đụn cát duy trì hình dáng đặc trưng (outline stays the same) mặc dù có di chuyển hay va chạm.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('9b6a841e-0d07-4c15-ad63-5831979a13a4', 'b0579c69-ec6c-4d40-8118-4f1c848840aa', 'matching', 'Questions 14-19', '', '<p>Write the correct number, <strong>i-vii</strong>, in boxes 14-19 on your answer sheet.</p>', 'matching_paragraph_information', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i New terminology reflecting changing attitudes to waste disposal"}, {"optionText": "ii Fundamental changes in behaviour in the past and future"}, {"optionText": "iii Ways of rewarding the public for recycling"}, {"optionText": "iv A surprising approach to waste disposal by several countries"}, {"optionText": "v Difficult choices for individuals and businesses"}, {"optionText": "vi Arguments against incineration from a country that uses it"}, {"optionText": "vii A number of justifications for the use of incineration"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Paragraph A — {iv. A surprising approach to waste disposal by several countries}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Norway, however, appears to be <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"43\">burning its way through a sizable chunk of Europe’s municipal waste</strong>, using the heat… to warm and power homes… Germany, Sweden, Belgium and the Netherlands all burn significant quantities…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Surprising approach” chính là việc các quốc gia này (Na Uy, Đức, Thụy Điển…) không chỉ đốt rác của mình mà còn nhập khẩu rác từ nước khác để biến thành năng lượng sưởi ấm. Đây là cách tiếp cận khá lạ lẫm so với quan niệm cũ rằng đốt rác là “lười biếng” hay độc hại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Paragraph B — {vii. A number of justifications for the use of incineration}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Those who support burning waste say that a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"55\">new generation of incinerators has made it a more attractive option</strong>. Filters and scrubbing mechanisms now capture harmful substances… Above all… incineration is the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"224\">only way of preventing the long-term impacts of landfill</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Justifications” (sự lý giải/bào chữa) nằm ở việc liệt kê các ưu điểm: công nghệ lọc khí thải hiện đại (filters/scrubbing), sự tiến hóa trong kỹ thuật đốt và là giải pháp cấp bách để thay thế bãi chôn lấp đang quá tải.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. Paragraph C — {vi. Arguments against incineration from a country that uses it}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“Lars Haltbrekken, chairman of Friends of the Earth in <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"66\">Norway [a country that uses it]</strong>, is concerned that incineration plants appear to generate demand… ‘But in a broader perspective, it’s a <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"204\">lazy way</strong> of getting rid of waste; you <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"242\">don’t stimulate the goals of reducing, reusing and recycling</strong>.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lars Haltbrekken (đại diện từ Na Uy – quốc gia đang đốt rác mạnh mẽ nhất) lại đưa ra các luận điểm phản đối (arguments against): việc xây quá nhiều nhà máy đốt rác khiến họ lười tái chế và làm giảm động lực thực hiện các mục tiêu bảo vệ môi trường bền vững.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Paragraph D — {i. New terminology reflecting changing attitudes to waste disposal}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“We used to call this the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"37\">‘cradle to grave’</strong> life cycle; now, the talk is of <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"87\">‘cradle to cradle’</strong> and an even more comprehensive concept known as <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"154\">‘zero waste’</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “New terminology” chính là các thuật ngữ mới như “Cradle to Cradle” (Từ nôi đến nôi) hay “Zero waste” (Không rác thải), phản ánh sự thay đổi trong tư duy: sản phẩm phải được thiết kế để tái sinh thay vì bị vứt bỏ sau khi sử dụng (Cradle to Grave).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. Paragraph E — {v. Difficult choices for individuals and businesses}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…it’s not always clear-cut… Supermarkets keep their shelves stocked even when demand isn’t there… <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"116\">that cost is less to them than the cost in brand damage of having empty shelves</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Difficult choices” ở đây là bài toán kinh tế khó khăn: Siêu thị (businesses) phải chọn giữa việc bỏ phí thức ăn (waste) hay để kệ hàng trống gây ảnh hưởng thương hiệu. Người tiêu dùng (individuals) cũng đối mặt với việc lãng phí thực phẩm trị giá hàng tỷ bảng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. Paragraph F — {ii. Fundamental changes in behaviour in the past and future}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“If someone back in the <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"35\">1980s [the past]</strong> had suggested what waste would be like now, they would be completely wrong… Consumerism has developed at a pace we never expected… Perhaps we can align the environmental message to these <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"243\">deep-seated values [the future]</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nhìn lại quá khứ (thập niên 80) để thấy rác thải điện tử và thói quen tiêu dùng đã thay đổi thế nào, đồng thời gợi mở về tương lai: cần thay đổi hành vi dựa trên các giá trị cốt lõi và vai trò dẫn dắt của chính phủ.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d644cb5c-8d5a-46aa-9145-58aa968f70be', '9ff836fa-ee1e-48fc-83c2-0d35886977e9', 'matching', 'Questions 11–16', NULL, '<p>What information does the tour guide give about each of the following products?</p>
<p>Choose <strong>SIX</strong> correct letters, <strong>A</strong>-<strong>l</strong>, next to questions 11-16.</p>
<p> </p>', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Products</strong></p>\n<p>hand cream {G popular overseas}</p>\n<p> </p>\n<p>jam {B expensive}</p>\n<p> </p>\n<p>soaps {A pure}</p>\n<p> </p>\n<p>candles {D best value for money}</p>\n<p> </p>\n<p>ice cream {H prize-winning}</p>\n<p> </p>\n<p>shampoo {F made in the village}</p>", "answerOptions": [{"optionText": "A pure"}, {"optionText": "B expensive"}, {"optionText": "C perfumed"}, {"optionText": "D best value for money"}, {"optionText": "E imported"}, {"optionText": "F made in the village"}, {"optionText": "G popular overseas"}, {"optionText": "H prize-winning"}, {"optionText": "I coloured"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a tour guide talking to a group of visitors about a farmers and growers market in a small New Zealand village. First you have some time to look at questions 11 to sixteen. Now listen carefully and answer questions 11 to sixteen.</p>\n<p><strong>Tour Guide (Helen):</strong> Welcome everyone to this farmers and growers market in the quiet village of Havelock North. My name is Helen and I’m your guide for the morning. Before I let you go off and explore, I’ll just tell you a few things first, which will help you know both what sort of products you will find here—there’s everything from fresh produce to handcrafts—and then how to find your way around.</p>\n<p>Right, so what do people sell here? Well, for a start, there’s some very nice <strong>hand cream</strong> from the Far North, which is always a top seller <strong>(11) abroad (G)</strong>. Those of you visitors who come from other countries may like to take it back home with you as presents because the packaging is branded ‘New Zealand’ and has pretty pictures on it of our native flowers.</p>\n<p>Now, there’s also some very tasty <strong>jam</strong> available, although because it’s made from blueberries, this product is quite <strong>(12) dear (B)</strong>, so you’ll have to spend a little more than usual. Still very delicious though!</p>\n<p>And for those of you who like your bath products gentle and suitable for sensitive skin, there are some non-allergenic <strong>soaps</strong> here. Not perfumed or coloured, just simple soap through and through, made by hand the old fashioned way with nothing artificial added <strong>(13) (A)</strong>.</p>\n<p>Ah, now there are the <strong>candles</strong> for sale at a very reasonable price. They probably represent the <strong>(14) top buy (D)</strong> if you want your dollar to stretch as far as possible. They’re just the colour of wax, so that’s not too exciting, but they do come in all different sizes to suit different purposes.</p>\n<p>Um, just a couple more items for me to tell you about. There’s great flavoured <strong>ice cream</strong> on offer. In fact, it’s so good that it’s classified export grade and was awarded the <strong>(15) gold medal (H)</strong> at this year’s food fair. You should try some!</p>\n<p>And finally, we’ve got <strong>shampoo</strong> which comes in cute little blue, green, and red bottles for three different hair types. The best thing about this product is that it’s produced right here in Havelock North <strong>(16) Village (F)</strong> by a farmer’s wife who started her own company.</p>\n<p><strong>Narrator:</strong> Before you hear the rest of the talk, you have some time to look at questions 17 to twenty. Now listen and answer questions 17 to twenty.</p>\n<p><strong>Tour Guide (Helen):</strong> Right, so that’s given you an idea of the sorts of products which are on sale at this market. Now let’s just give you a quick rundown on where to find everything, then I’ll let you go for a walk around to do your shopping.</p>\n<p>As you enter the market through the gate here in front of us, at the bottom of the map you’ve been given, you’ll see immediately that the farmers have set up their stalls out in a square in the middle of the Vineyard.</p>\n<p>I know a few of you are interested in buying <strong>(17) wooden</strong> handicrafts, so just to let you know that the stall is located on the far side of the walking track <strong>opposite the entrance (B)</strong>. There are some lovely toys for sale there and also hand-carved wooden platters and bowls.</p>\n<p>Now, the first one you’d see to your left after entering, tucked away there by the gate, is the <strong>(18) China</strong> Store <strong>(H)</strong> where there’s an interesting display of old, second-hand or antique teacups and saucers.</p>\n<p>What else? Oh, yes, the <strong>(19) Wool</strong> Shop. For those of you who are wanting to take home a New Zealand sheepskin rug or a woolly Jersey for the winter, can be found on your immediate <strong>right after you’ve gone in the entrance (E)</strong>. There are some nice scarves and hats there too.</p>\n<p>Now after all this shopping, you’ll be needing a <strong>(20) drink</strong> and something to eat, so go into the circular stand in the middle and you’ll find a stall selling local wine, fruit juices and cordials, and that’s the one at the centre <strong>top, furthest away from the main gate (G)</strong>. And also a store with lots of snack food to keep you going.</p>\n<p>Well, that’s all for me folks, now enjoy the market.</p>\n<p><strong>Narrator:</strong> That is the end of part 2. You now have 30 seconds to check your answers to part two.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('750f3535-54d5-4ecb-9893-47cc8a959ba8', '9ff836fa-ee1e-48fc-83c2-0d35886977e9', 'matrix', 'Questions 17–20', NULL, '<p>Label the map below.</p>
<p>Choose the correct letter, <strong>A-H</strong></p>
<p>  <img src="data:image/png;base64," width="580" height="419" loading="lazy"></p>', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Wood", "correctCategoryLetter": "B"}, {"itemText": "China", "correctCategoryLetter": "H"}, {"itemText": "Wool", "correctCategoryLetter": "E"}, {"itemText": "Drinks", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": ""}]', 1);
INSERT INTO public.questions VALUES ('660ef8e2-d22b-4c83-88df-7a6ccc74a154', '9b67ed03-0086-4f82-9095-f3620fcf1f29', 'radio', 'Questions 21–25', NULL, '<p>Choose the correct answer.</p>
<p><span style="font-size: 12pt;"><strong>Group Project</strong></span></p>', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A finished planting the experiment."}, {"content": "B taken an extended break."}, {"content": "C spent a lot of time in the laboratory."}], "question": "Jen states that Irene has recently"}, {"correct": 0, "options": [{"content": "A He is grateful for her contribution."}, {"content": "B He thinks she is stylish."}, {"content": "C He resents her avoiding lab work."}], "question": "What is Bill''s attitude toward Kim?"}, {"correct": 1, "options": [{"content": "A would be easier for boys good at maths."}, {"content": "B would fail without Kim and Irene''s input."}, {"content": "C is almost done because Kim has finished the data analysis."}], "question": "Jen believes that their project"}, {"correct": 1, "options": [{"content": "A she is always late with her work."}, {"content": "B she fails to keep in touch enough."}, {"content": "C she thinks the project is an easy grade."}], "question": "Bill and Jen are irritated with Linda because"}, {"correct": 1, "options": [{"content": "A is popular with everyone on the team."}, {"content": "B always reads all of her assignments."}, {"content": "C enjoys talking to Professor Cooper."}], "question": "Jen was asked to join the team because she"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: GROUP PROJECT</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Bill:</strong> What’s up, Jen? How are you?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Jen:</strong> Oh hey, Bill.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Bill:</strong> Where’s everybody else?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Jen:</strong> I don’t know, you’re the first to get here.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Bill:</strong> Well, I hope they don’t take too long. I have a class at noon.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Jen:</strong> Why don’t we at least discuss what we’ve completed and what’s left to do?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Bill:</strong> Sounds like a plan. Have you heard anything from Irene?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Jen:</strong> Yeah, Irene told me the experiment is just about done. <span style=\"text-decoration: underline;\"><span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"60\">(21) She’s been practically living in the lab the past week.</strong></span></span></p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Bill:</strong> Wow, we owe her a favor, don’t we?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Jen:</strong> You can say that again.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Bill:</strong> Has Kim been helping her? I thought that lab work was not her style.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Jen:</strong> Well, not so much in the lab, but she has started compiling the data for the analysis.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Bill:</strong> <strong data-path-to-node=\"15\" data-index-in-node=\"6\"><span style=\"text-decoration: underline; background-color: #f3db7b;\">(22) Kim is terrific</span>.</strong> I hate doing stats. I’ve always been bad at math.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Jen:</strong> I always thought there wasn’t anything to that “boys are good at math” theory, haha.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Bill:</strong> Yes, and I’m proof!</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Jen:</strong> Anyway, Kim hasn’t actually run the stats for the project yet since she still has to wait for the rest of the experiment data, but she’s ready to get started when we get the experiment done. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"18\" data-index-in-node=\"196\">(23) Seriously, without Irene and Kim, we’d be in trouble.</strong></span></p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Bill:</strong> Yeah, you’re right about that. So what about Linda? What’s she been up to?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Jen:</strong> Who knows? All she ever talks about is her fiancé. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"20\" data-index-in-node=\"56\">(24) I haven’t seen or heard from her all week.</strong></span></p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Bill:</strong> Well, I hope she turns up soon. We’ll need everyone if we’re going to get this done on time.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Jen:</strong> Yeah, and she knows that Professor Cooper is a hard grader of projects. I’m worried that Professor Cooper is not going to give us a passing grade anyway. We haven’t talked about the introduction yet. Have you finished reading those articles Professor Cooper gave us?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Jen:</strong> Bill, she gave us those two weeks ago!</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Bill:</strong> Hey, I’ve been busy and I haven’t…</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Jen:</strong> Come on, Bill!</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Bill:</strong> Oh Jen, you know we all depend on you for that. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"26\" data-index-in-node=\"54\">(25) You’re the only person I know that reads every assignment from beginning to end.</strong></span> You and Professor Cooper often have private discussions about readings in the middle of class.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Bill:</strong> I’m not complaining! That’s why all the rest of us asked you to be on our team.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Jen:</strong> Oh, so that’s why!</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Bill:</strong> Yeah.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Jen:</strong> So it wasn’t because I’m popular, huh?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Bill:</strong> Hey, you’re the best. No one’s gonna argue that.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Bill:</strong> Hey, I’m thirsty. You want something to drink?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Jen:</strong> No, I’m good.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Bill:</strong> Okay, I’ll be right back.</p>\n<hr data-path-to-node=\"35\">\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">ASSIGNING RESPONSIBILITIES</strong></p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Jen:</strong> They’re still not here?</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Bill:</strong> Nope, and I’ve got a class I gotta get to.</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Jen:</strong> Well, let’s divide up responsibilities, like who’s responsible for each section. It only makes sense that <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"39\" data-index-in-node=\"111\">(26) Irene writes up all the materials and methods</strong></span>, since she spent the most time with that.</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Bill:</strong> Oh, that’s easy.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Jen:</strong> Hey, didn’t you just say we owe her one?</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Bill:</strong> Yeah, yeah, you’re right. Irene can do the methodology section.</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Jen:</strong> Do you wanna do the results?</p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Bill:</strong> Not at all. I thought Kim would do that.</p>\n<p data-path-to-node=\"45\"><strong data-path-to-node=\"45\" data-index-in-node=\"0\">Jen:</strong> Just because she is good at stats, doesn’t mean she’ll be good at writing it up. And besides, you are the one good at copy editing.</p>\n<p data-path-to-node=\"46\"><strong data-path-to-node=\"46\" data-index-in-node=\"0\">Bill:</strong> Well, all the same, I think it’ll be easiest if <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"46\" data-index-in-node=\"54\">(27) she (Kim) does the results section.</strong></span> I’ll edit the whole report.</p>\n<p data-path-to-node=\"47\"><strong data-path-to-node=\"47\" data-index-in-node=\"0\">Jen:</strong> Come on, that’s asking a lot of you.</p>\n<p data-path-to-node=\"48\"><strong data-path-to-node=\"48\" data-index-in-node=\"0\">Bill:</strong> Well, what part are you gonna do, Jen?</p>\n<p data-path-to-node=\"49\"><strong data-path-to-node=\"49\" data-index-in-node=\"0\">Jen:</strong> Isn’t that obvious? Since I’m the one who does all the reading,</p>\n<p data-path-to-node=\"50\"><strong data-path-to-node=\"50\" data-index-in-node=\"0\">Bill:</strong> I’m sure<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"50\" data-index-in-node=\"15\">(28) you’ll (Jen) give us the best literature review.</strong> </span></span>We’re all counting on you for that.</p>\n<p data-path-to-node=\"51\"><strong data-path-to-node=\"51\" data-index-in-node=\"0\">Jen:</strong> I guess that leaves the discussion section and the bibliography.</p>\n<p data-path-to-node=\"52\"><strong data-path-to-node=\"52\" data-index-in-node=\"0\">Bill:</strong> Yeah, can you make suggestions on these?</p>\n<p data-path-to-node=\"53\"><strong data-path-to-node=\"53\" data-index-in-node=\"0\">Jen:</strong> Okay, but seriously, wouldn’t it make more sense if<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"53\" data-index-in-node=\"57\">(29) you (Bill) do the list of references?</strong></span></span></p>\n<p data-path-to-node=\"54\"><strong data-path-to-node=\"54\" data-index-in-node=\"0\">Jen:</strong> There are enough commas, capital letters, and parentheses to keep you happy in there, haha.</p>\n<p data-path-to-node=\"55\"><strong data-path-to-node=\"55\" data-index-in-node=\"0\">Bill:</strong> Yeah, you got a point. It sure does make sense that I do the bibliography…</p>\n<p data-path-to-node=\"56\"><strong data-path-to-node=\"56\" data-index-in-node=\"0\">Jen:</strong> I guess<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"56\" data-index-in-node=\"13\">(30) Linda could handle the discussion section</strong>,</span></span> even if she hasn’t been around much.</p>\n<p data-path-to-node=\"57\"><strong data-path-to-node=\"57\" data-index-in-node=\"0\">Bill:</strong> Yeah, but isn’t that like the most important section?</p>\n<p data-path-to-node=\"58\"><strong data-path-to-node=\"58\" data-index-in-node=\"0\">Jen:</strong> Well, what else is she going to do?</p>\n<p data-path-to-node=\"59\"><strong data-path-to-node=\"59\" data-index-in-node=\"0\">Bill:</strong> The whole paper? It’ll serve her right.</p>\n<p data-path-to-node=\"60\"><strong data-path-to-node=\"60\" data-index-in-node=\"0\">Jen:</strong> Then we’d all fail!</p>\n<p data-path-to-node=\"61\"><strong data-path-to-node=\"61\" data-index-in-node=\"0\">Bill:</strong> Okay, but I think we all should start messaging her to make sure she gets busy. The discussion section can be long.</p>\n<p data-path-to-node=\"62\"><strong data-path-to-node=\"62\" data-index-in-node=\"0\">Jen:</strong> What about the abstract?</p>\n<p data-path-to-node=\"63\"><strong data-path-to-node=\"63\" data-index-in-node=\"0\">Bill:</strong> You really don’t want me to do the abstract, do you?</p>\n<p data-path-to-node=\"64\"><strong data-path-to-node=\"64\" data-index-in-node=\"0\">Jen:</strong> That’s not the point. I just think that the abstract should be for whoever finishes first,</p>\n<p data-path-to-node=\"65\"><strong data-path-to-node=\"65\" data-index-in-node=\"0\">Bill:</strong> right.</p>"}]', 0);
INSERT INTO public.questions VALUES ('8ee13fda-bc5f-428a-a16d-891b2f03ee78', '0b52d227-9178-48ac-985c-e13b7bb2dcbf', 'matching', 'Questions 27–33', NULL, '<p>Reading Passage 3 has seven paragraphs, <strong>A-G</strong>.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, <strong>i-viii</strong>, in boxes <strong>27-33</strong>.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. A negative reaction to receiving flowers"}, {"optionText": "ii. Some surprisingly strong responses to flowers"}, {"optionText": "iii. A mutually beneficial relationship?"}, {"optionText": "iv. Becoming more open about personal matters"}, {"optionText": "v. Some common social functions of flowers"}, {"optionText": "vi. Sensory appeal versus practical purpose of flowers"}, {"optionText": "vii. Bridging the gap between strangers in an enclosed space"}, {"optionText": "viii. An imperfect theory"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>27. Paragraph A</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong>Đáp án:</strong> <strong>v. Some common social functions of flowers</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) Đoạn này liệt kê các mục đích xã hội phổ biến khi tặng hoa: <strong>để chia buồn, ăn mừng, tán tỉnh, xin lỗi</strong> (<em>“To offer condolence… To celebrate. To woo. To ask for forgiveness”</em>).</li>\n</ul>\n<p><strong>28. Paragraph B</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong>Đáp án:</strong> <strong>iv. Becoming more open about personal matters</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) Những người nhận hoa được đánh giá là có tâm trạng tích cực hơn và <strong>sẵn lòng trả lời các câu hỏi về vòng tròn xã hội và các cuộc trò chuyện thân mật</strong> (<em>“more willing to answer questions concerning their social circle and intimate conversations”</em>).</li>\n</ul>\n<p><strong>29. Paragraph C</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong>Đáp án:</strong> <strong>vii. Bridging the gap between strangers in an enclosed space</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) Nghiên cứu diễn ra trong thang máy (<em>“inside an elevator”</em>), một không gian kín. Những người nhận hoa <strong>thu hẹp khoảng cách</strong> (<em>“closed up that space to a considerable extent”</em>) và tăng sự thân mật (<em>“significant affiliation”</em>) với người lạ.</li>\n</ul>\n<p><strong>30. Paragraph D</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong>Đáp án:</strong> <strong>ii. Some surprisingly strong responses to flowers</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) Một số đối tượng đã thể hiện <strong>sự bộc lộ cảm xúc phi thường</strong> (<em>“extraordinary emotional displays”</em>), chẳng hạn như <strong>ôm và hôn tự phát</strong> (<em>“spontaneous hugs and kisses”</em>) người giao hoa, điều mà các nhà tâm lý học không lường trước được.</li>\n</ul>\n<p><strong>31. Paragraph E</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong>Đáp án:</strong> <strong>viii. An imperfect theory</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) Đoạn này đưa ra một giả thuyết tiến hóa giải thích sở thích đối với hoa, nhưng sau đó chỉ ra <strong>sai sót</strong> (<em>“flaw in this argument”</em>) của nó (hoa đẹp nhất không cho ra sản phẩm ăn được).</li>\n</ul>\n<p><strong>32. Paragraph F</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong>Đáp án:</strong> <strong>vi. Sensory appeal versus practical purpose of flowers</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) Đoạn này so sánh sự hấp dẫn <strong>cảm giác</strong> (<em>“Sensory appeal”</em>) của màu sắc, kết cấu và mùi hương hoa với mục đích tiến hóa ban đầu (tìm trái cây chín), và kết luận rằng sự yêu thích đã <strong>tách rời khỏi mục đích tiến hóa chính</strong> (<em>“long been separated from their primary evolutionary use”</em>).</li>\n</ul>\n<p><strong>33. Paragraph G</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong>Đáp án:</strong> <strong>iii. A mutually beneficial relationship?</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) Lý thuyết của nhóm Rutgers đề xuất mối quan hệ <strong>đồng tiến hóa giữa thực vật và con người</strong> (<em>“plant-human co-evolution”</em>), trong đó hoa khai thác (<em>“exploit”</em>) cảm xúc của con người. Tác giả kết luận: “they are using you just as much as you are using them” (mối quan hệ đôi bên cùng có lợi/mutually beneficial).</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('6ce70a78-f0fe-4a51-8789-50b884b7b692', '9b67ed03-0086-4f82-9095-f3620fcf1f29', 'matching', 'Questions 26–30', NULL, '<p>Which section will each of the following group members write up?</p>
<p>Choose <strong>FIVE </strong>correct letters.</p>', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Group members</strong></p>\n<p> </p>\n<p>Irene {F Methodology}</p>\n<p> </p>\n<p>Kim {G Results}</p>\n<p> </p>\n<p>Jen {E Literature review}</p>\n<p> </p>\n<p>Bill {C Bibliography}</p>\n<p> </p>\n<p>Linda {D Discussion}</p>", "answerOptions": [{"optionText": "A Abstract"}, {"optionText": "B Acknowledgements"}, {"optionText": "C Bibliography"}, {"optionText": "D Discussion"}, {"optionText": "E Literature review"}, {"optionText": "F Methodology"}, {"optionText": "G Results"}], "matchingItems": null}', 'null', '[{"content": ""}]', 1);
INSERT INTO public.questions VALUES ('de9ad353-9ea4-472a-a952-76ff39022245', 'cab7ad48-72bb-41a1-8873-351ff21253a1', 'radio', 'Questions 11–13', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>
<p data-start="85" data-end="116"><strong>Becoming a volunteer for ACE</strong></p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A They are too small."}, {"option_text": "B There are not enough of them"}, {"option_text": "C Some of them are very close together"}], "question": "Why does the speaker apologise about the seats?"}, {"correct": 0, "options": [{"option_text": "A The age of volunteers is less important than other factors."}, {"option_text": "B Young volunteers are less reliable than older ones."}, {"option_text": "C Most volunteers are about 60 years old."}], "question": "What does the speaker say about the age of volunteers?"}, {"correct": 0, "options": [{"option_text": "A It is continuous."}, {"option_text": "B It is conducted by a manager."}, {"option_text": "C It takes place online."}], "question": "What does the speaker say about training?"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('5fd8cf16-e889-4542-9298-c9e0beac9443', 'cab7ad48-72bb-41a1-8873-351ff21253a1', 'checkbox', 'Questions 14 and 15', '', '<p data-start="671" data-end="695">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="697" data-end="795">Which <strong>TWO </strong>issues does the speaker ask the audience to consider before they apply to be volunteers?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A their financial situation"}, {"correct": true, "option_text": "B their level of commitment"}, {"correct": false, "option_text": "C their work experience"}, {"correct": false, "option_text": "D their ambition"}, {"correct": true, "option_text": "E their availability"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('89fbcc88-cc53-4773-bec7-7f5a68fd551a', '8cd27c1c-cf3a-47ba-8210-25300fb769e7', 'fillup', 'Questions 31-40', '<p><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Complete the notes below.</span></p>
<p><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Write <strong style="mso-bidi-font-weight: normal;">NO MORE THAN TWO WORDS</strong> for each answer.</span></p>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Impact of cars in Australia (1940s – 1990s)</span></strong></p>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">1940s</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l4 level1 lfo1; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">One person in eight owned a car</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l4 level1 lfo1; tab-stops: list .5in; vertical-align: baseline;"><strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: black;">{public}</span></strong><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> transport was used for 60% of journeys</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l4 level1 lfo1; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Buses:</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Problems – crowded and {uncomfortable}</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Advantage – affordable</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l2 level1 lfo2; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">Cars were associated with {freedom}</span></span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l2 level1 lfo2; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Problems of car ownerships</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">i. cost</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">ii. many spare parts were imported</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">iii. restrictions on fuel</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">iv. high {taxes}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;"> on cars</span></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l0 level1 lfo3; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Result of pressure form motorists – new {government}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> in Australia in 1949</span></li>
</ul>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">1960s</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l5 level1 lfo4; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Cars were cheaper and more reliable</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l5 level1 lfo4; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">More people lived in the suburbs</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l5 level1 lfo4; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Main streets were congested and {polluted}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> (and usually straight)</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l5 level1 lfo4; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">New streets were built with curves to make drivers slow down</span></li>
</ul>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">1970s</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l3 level1 lfo5; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">Roads had more {lanes}</span></span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l3 level1 lfo5; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">More commuters</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l3 level1 lfo5; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Car use affected the {relationships}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> between people</span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l3 level1 lfo5; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">New types of {advertisements}</span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"> were designed to attract motorists</span></li>
</ul>
<p><strong style="mso-bidi-font-weight: normal;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">1980s and 1990s</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l1 level1 lfo6; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">Less business in town centres because of introduction of {shopping malls}</span></span></li>
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-outline-level: 3; mso-list: l1 level1 lfo6; tab-stops: list .5in; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">Introduction of drive-in facilities, e.g. restaurants</span></li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Lecturer:</strong> Good morning everyone. Today in this second lecture of the series, we turn our attention to transportation. In particular, we’re going to take a look at the way the motor car influenced urban development in Australia and changed our lifestyle from the 1940s to the end of the 1990s.</p>\n<p>The car is so common nowadays that we all take it for granted and we barely think about the major effect it has had on our society. But let’s go back for a while to the late 1940s. Although they had been around since the start of the 20th century, only one person in eight owned a car in Australia’s major cities at that time. Nearly <strong>(31) 60% of journeys</strong> were still made by various means of <strong>public</strong> transport, and only 15% by car, which is clearly very few compared to statistics now.</p>\n<p>Buses were very crowded in the days before extensive car use, and they were also considered to be <strong>(32) uncomfortable</strong>, despite providing a cheap option that most people could afford. Remember this wasn’t long after the Second World War. People were tired of living without things, of making do, and to them cars represented <strong>(33) freedom</strong>.</p>\n<p>But even for the wealthy few who did have vehicles, it wasn’t easy to run a car at this time. As well as the expense of buying a car, spare parts were difficult to get as many were imported. Another problem for car owners was that fuel was still rationed, and car <strong>(34) taxes</strong> were very high. Strong public feeling on issues like these from various pressure groups resulted in a change of <strong>(35) government</strong> in Australia after the general election in 1949, which undoubtedly shaped the future of our nation.</p>\n<p> In the 1960s, cheaper, more reliable cars became available, and this coincided with the rapid expansion of the suburbs. The car enabled these to grow in all directions, far beyond the train lines laid down in the 19th century. For the previous 150 years, the city centre had been a prestigious area, but the addition of cars made the main streets congested. This wasn’t the only problem; now they were <strong>(36) polluted</strong> as well.</p>\n<p>Since these streets were usually straight, they tempted motorists to speed, so the layout of newer streets was affected by this change towards private transport. In the newer areas roads were no longer built straight; instead they had curves that were specially designed to force drivers to slow down. This meant they were longer, but this was not a problem because people rarely walked anymore.</p>\n<p> By the 1970s the type of roads being built changed, with more <strong>(37) lanes</strong> in each direction. There were more commuters because now there was faster access to the city where they worked. By this time the motor car was affecting many different areas of life. It even surprisingly affected <strong>(38) relationships</strong>. Before this meeting, anyone who lived beyond walking or cycling distance was impractical, if not impossible. The car brought people together.</p>\n<p>What other effects did the car have? The increase in car use changed the way we advertise. Previously, advertisements had been designed to attract slow-moving pedestrians, so they were located at eye level and designed on a human scale. By the late 1970s, massive <strong>(39) advertisements</strong> were designed to attract the notice of the passing motorist.</p>\n<p> In the 1980s and 90s, even the location of shops began to change. We built <strong>(40) shopping malls</strong> out in the suburbs, which meant that Old Town centres did far less business. Next, we saw the development of drive-in shopping centres, theatres and even restaurants, which now ensure we get out of our cars as little as possible.</p>\n<p>Now, I’d like to turn your attention to a few statistics related to car ownership over the same period…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('3728ea47-d8a7-4dd7-9f82-71d7bdd6d4df', 'cab7ad48-72bb-41a1-8873-351ff21253a1', 'matrix', 'Questions 16–20', '', '<p data-start="949" data-end="1046">What does the speaker suggest would be helpful for each of the following areas of voluntary work?</p>
<p data-start="1048" data-end="1140">Choose <strong>FIVE </strong>answers from the box and write the correct letter, <strong>A</strong>–<strong>G</strong>, next to Questions 16–20.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "Fundraising", "correctCategoryLetter": "B"}, {"itemText": "Litter collection", "correctCategoryLetter": "G"}, {"itemText": "‘Playmates’", "correctCategoryLetter": "D"}, {"itemText": "Story club", "correctCategoryLetter": "A"}, {"itemText": "First aid", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "experience on stage", "categoryLetter": "A"}, {"categoryText": "original, new ideas", "categoryLetter": "B"}, {"categoryText": "parenting skills", "categoryLetter": "C"}, {"categoryText": "an understanding of food and diet", "categoryLetter": "D"}, {"categoryText": "retail experience", "categoryLetter": "E"}, {"categoryText": "a good memory", "categoryLetter": "F"}, {"categoryText": "a good level of fitness", "categoryLetter": "G"}]}', 'null', 2);
INSERT INTO public.questions VALUES ('9ce6b3d6-ca62-4855-ab8a-89e9938ade18', '194a8ee8-b399-42ca-8ef6-3baf4dc1e427', 'fillup', 'Questions 37–40', '<p>Complete the summary below.</p>
<p>Write<strong> NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>Singing dunes</strong></p>
<p>Singing dunes, which belong to the type of dunes known as {barchans dunes| barchans}, produce a very loud sound which is transmitted at a low frequency. Researchers have worked out that sand grains fall down the dune and start vibrating against other grains, forming a sound wave.</p>
<p>Research proves that the individual grains have a similar {shape}, but the differences in dimensions alter the {tone}, of the ‘song’. Each grain is covered with a mixture of different {minerals}, and this is vital to the sound production.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>37. Singing dunes, which belong to the type of dunes known as barchans dunes/ barchans , produce a very loud sound…</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> barchans dunes | barchans</p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn F) “…some <strong>barchans</strong> actually sing.”</p>\n</li>\n</ul>\n<p><strong>38. Research proves that the individual grains have a similar shape…</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>shape</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn G) “Their studies show the grains are a <strong>uniform shape</strong>…”</p>\n</li>\n</ul>\n<p><strong>39. …but the differences in dimensions alter the tone of the ‘song’.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>tone</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn G) “…the variations in size affect the <strong>tone</strong>.”</p>\n</li>\n</ul>\n<p><strong>40. Each grain is covered with a mixture of different minerals and this is vital to the sound production.</strong></p>\n<ul>\n<li>\n<p><strong>Đáp án:</strong> <strong>minerals</strong></p>\n</li>\n<li>\n<p><strong>Dẫn chứng:</strong> (Đoạn G) “…coated with a special veneer… made from a precise combination of <strong>minerals</strong> from surrounding rocks…”</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('c2cf520a-4662-4598-ba0a-5576fb0a43b9', 'c09ee800-0d6b-47ee-bfa4-c4e3bd5263b3', 'checkbox', 'Questions 23 and 24', '', '<p><span class="citation-24812">Choose </span><strong data-path-to-node="11" data-index-in-node="7"><span class="citation-24812">TWO</span></strong><span class="citation-24812"> letters, </span><strong data-path-to-node="11" data-index-in-node="20"><span class="citation-24812">A–E</span></strong><span class="citation-24812 citation-end-24812">.<sup class="superscript" data-turn-source-index="45"><!----></sup></span></p>
<p><span class="citation-24811 citation-end-24811">Write the correct letters in boxes 23 and 24 on your answer sheet.</span></p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A the stage at which she dropped out of the tournament"}, {"correct": true, "option_text": "B symptoms of her performance stress at the tournament"}, {"correct": false, "option_text": "C measures which she had taken to manage her stress levels"}, {"correct": true, "option_text": "D aspects of the Wimbledon tournament which increased her stress levels"}, {"correct": false, "option_text": "E reactions to her social media posts about her experience at Wimbledon"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">23.B. symptoms of her performance stress at the tournament — {ĐÚNG}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"...she began having <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"41\">difficulty regulating her breathing and heart rate</strong> during a match...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Difficulty regulating her breathing and heart rate\" (khó khăn trong việc điều chỉnh nhịp thở và nhịp tim) chính là những triệu chứng vật lý (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"154\">symptoms</strong>) của tình trạng căng thẳng mà cô gặp phải ngay tại giải đấu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">24.D. aspects of the Wimbledon tournament which increased her stress levels — {ĐÚNG}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"...in Emma Raducanu''s case, a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"51\">much larger audience</strong>, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"73\">higher expectations</strong> and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"97\">facing a more skilful opponent</strong>, may all have led her to feel there were greater demands being placed on her at Wimbledon...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các yếu tố (aspects) như: khán giả đông hơn rất nhiều, kỳ vọng cao hơn và đối thủ kỹ năng tốt hơn chính là những tác nhân làm tăng mức độ stress của cô tại Wimbledon.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('33efe66a-4d49-43fa-b73b-262244f023b7', 'b51a7ed3-9516-492e-b796-304d93cfbf62', 'matching', 'Questions 27–30', NULL, '<p>According to Ted, what is the right way to make a successful presentation?</p>
<p>Choose <strong>FOUR </strong>letters from the box and write the correct letter, <strong>A–F</strong>, next to questions 27–30.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p>Step 1. Write {D. an introduction}</p>\r\n<p>Step 2. {G. research} further on the topic</p>\r\n<p>Step 3. Put a {E. statement} for every picture and support it</p>\r\n<p>Step 4. Every slide illustrates a thought, all the thoughts link together</p>\r\n<p>Step 5. Write {A. text handouts}</p>", "answerOptions": [{"optionText": "A. text handouts"}, {"optionText": "B. questions"}, {"optionText": "C. an outline"}, {"optionText": "D. an introduction"}, {"optionText": "E. statement"}, {"optionText": "F. explain"}, {"optionText": "G. research"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('ea22be60-e9dc-4749-a56a-574df7c7aeb7', '95d4b4ef-2803-4f2e-8ceb-ea411b28caae', 'matrix', 'Questions 18 - 21', '', '<p>Write the correct letter, <strong>A-E</strong>, in boxes 18-21 on your answer sheet.<br><strong>NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of People", "matrixItems": [{"itemText": "We changed our farm because of what people around us were doing.", "correctCategoryLetter": "B"}, {"itemText": "Today''s problems with biodiversity have older origins than people realise.", "correctCategoryLetter": "E"}, {"itemText": "Farmers are more cautious about water use than non-farmers realise.", "correctCategoryLetter": "B"}, {"itemText": "The number of naturally occurring species has been seriously reduced by modern farming", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "Graham Robertson", "categoryLetter": "A"}, {"categoryText": "Richard Johnson", "categoryLetter": "B"}, {"categoryText": "Murray Rogers", "categoryLetter": "C"}, {"categoryText": "Colin Meurk", "categoryLetter": "D"}, {"categoryText": "Keith Woodford", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">18. We changed our farm because of what people around us were doing. — {B. Richard Johnson}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Mid-Canterbury farmer <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"43\">Richard Johnson</strong>… converted from growing crops to dairy farming five years ago, because he could see himself <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"153\">getting left behind by neighbours who’d made the switch</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Richard Johnson quyết định chuyển đổi (changed/converted) trang trại của mình vì thấy các hàng xóm (neighbours – tương ứng với “people around us”) đã chuyển đổi hết và ông không muốn bị bỏ lại phía sau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">19. Today’s problems with biodiversity have older origins than people realise. — {E. Keith Woodford}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“However, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"30\">Keith Woodford</strong>… doesn’t accept that dairying is responsible for this problem… Much of the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"124\">degradation you see in lowland areas is actually the result of practices going back to the 1960s</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Older origins” tương ứng với việc các vấn đề này bắt nguồn từ tận những năm 1960 (going back to the 1960s). Keith Woodford nhấn mạnh rằng sự suy thoái không phải do kỹ thuật canh tác hiện đại mà có nguồn gốc từ lâu hơn mọi người vẫn tưởng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">20. Farmers are more cautious about water use than non-farmers realise. — {B. Richard Johnson}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">Public perception</strong> is that this water is being wasted,’ says <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"81\">Johnson</strong>. ‘But <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"95\">farmers think long and hard before they turn the irrigation on</strong>, because it’s expensive.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong khi dư luận (public perception/non-farmers) nghĩ rằng nước đang bị lãng phí, thì Richard Johnson khẳng định nông dân phải cân nhắc rất kỹ (think long and hard/cautious) vì chi phí sử dụng nước rất đắt đỏ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">21. The number of naturally occurring species has been seriously reduced by modern farming — {D. Colin Meurk}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Another critic is <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"39\">ecologist Colin Meurk</strong>, who argues that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"78\">dairying has caused serious damage to Canterbury’s biodiversity</strong>… found that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"156\">precious little native habitat has survived</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Naturally occurring species” chính là các loài bản địa (native habitat/species). Colin Meurk lập luận rằng việc nuôi bò sữa (dairying/modern farming) đã gây thiệt hại nghiêm trọng khiến rất ít loài bản địa còn sống sót (seriously reduced).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('c5e58e44-1261-43c2-aaea-870de8308917', '7da8f4fd-f552-42ac-aa6e-17bc336029ec', 'checkbox', ' Questions 21–22', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>points did students most frequently make about their musical background before starting a music degree?</p>
', 'multiple_choice_many', 'null', '[{"option": "They had already composed music.", "correct": false}, {"option": "They had several music qualifications.", "correct": false}, {"option": "They could play more than one instrument.", "correct": true}, {"option": "They had performed in public.", "correct": true}, {"option": "They had had piano lessons.", "correct": false}]', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 3</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Gareth:</strong> So Gareth, we need to organize the findings from our survey on music students for the final presentation.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Lona:</strong> Yes Lona, I think we’ve got some very interesting results. Obviously we need to start by saying that we interviewed all the third-year students doing a music degree and state the objective of our research project, that is to find out about their attitudes to performing.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Gareth:</strong> And then we should talk about the students’ musical backgrounds before coming to university. The most important points to make are that although most people have actually composed music during the course, that wasn’t the case when they arrived. And the other thing they had in common was the piano—well they’d had access to a piano at some point, but not all had studied it formally. I thought the most interesting finding was that before coming here, almost everyone was involved in a chamber orchestra or band or singing in a choir and <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"5\" data-index-in-node=\"546\">(21/22) playing in front of live audiences (D: performed in public)</strong></span>, but varying enormously in size. Some had only played in tiny venues. I think it’s worth saying that.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Lona:</strong> OK. And as you might expect from people wanting to study music, they all had a degree of <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"95\">(21/22) proficiency in at least two instruments (C: play more than one instrument)</strong></span>, but in most cases one of the instruments was dominant.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Gareth:</strong> Right. We need to talk about attitudes to music practice. The most striking thing here is that even students who you’d expect to practice for hours every day until they get it perfect say it’s <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"7\" data-index-in-node=\"201\">(23/24) being terrified of failing that really makes them practice (C: motivated by fear)</strong></span>.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Lona:</strong> I know, I’m the same.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Gareth:</strong> Me too! It’s interesting what was said about practicing alone. Some people preferred that because they could focus more on their weak points, but that wasn’t a majority view. What most of them agree on is that there’s <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"9\" data-index-in-node=\"226\">(23/24) nothing more rewarding than mastering something that’s really hard to learn (E: enjoy the challenge of a difficult piece)</strong></span>.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Lona:</strong> That’s right. Okay, after that we should talk a bit about the pieces that students select for assessed performances. There wasn’t quite so much consensus on this, was there? A few people prefer to do pieces which are relatively unknown, while others choose the ones they think will show off their technical ability, but they were in the minority.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Gareth:</strong> Hmm. I think the first thing to say is that a high percentage said they would<span style=\"text-decoration: underline;\"> <span style=\"background-color: #fbeeb8;\"><strong data-path-to-node=\"11\" data-index-in-node=\"86\">(25/26) always try to learn their pieces by heart (C: play from memory)</strong></span></span> because it’s too easy to get lost if you’re trying to read and play when you’re nervous.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Lona:</strong> Hmm okay. And quite a lot of them said <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"12\" data-index-in-node=\"45\">(25/26) it helps to listen to other people playing your chosen piece (A: hear others performing)</strong></span>, preferably recordings but even just other students.</p>\n<hr data-path-to-node=\"13\" />\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Gareth:</strong> So finally, we need to look at the findings for students’ attitudes to performing. We should point out that this includes informal and formal public performances as well as assessed ones.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Lona:</strong> Yes, that’s important. I expected to find that performing solo would make students very nervous but in fact that isn’t the case. They do find it <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"15\" data-index-in-node=\"151\">(27) hugely challenging to start with, but they appreciate the challenge and find it stimulating (B: difficult but enjoyable)</strong></span>.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Gareth:</strong> Right. I was surprised by what students said about deciding which pieces to perform. I thought they’d all say this was easy. For me it’s always been quite straightforward: which pieces do I like best and which pieces can I play well? And my repertoire is quite limited anyway. But the most commonly cited answer was that <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"16\" data-index-in-node=\"329\">(28) it took them ages to make their minds up (E: time-consuming)</strong></span>. I suppose it’s because there are so many factors involved—you need to consider your audience, the venue, the time available to learn the piece, especially if it’s complicated. You need to think about all these things and you can’t do that in a hurry.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Lona:</strong> That’s true. Then there’s performing with musicians from a different genre, like a classical musician playing with a jazz group. That can really be fun, but <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"17\" data-index-in-node=\"163\">(29) most of the music students had never even considered it (G: happens infrequently)</strong>.</span></p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Gareth:</strong> Right. For performing with musicians who play the same instrument, almost everyone put the same thing. Yes, they all said <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"18\" data-index-in-node=\"130\">(30) it was incredibly helpful (A: very beneficial)</strong></span> and not at all intimidating, which says a lot for the department’s ethos.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Lona:</strong> Yes, that’s a good point. Okay, what I think we should sort out now is…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('67f8b98b-eba9-4360-9a44-23763214d5ec', '7da8f4fd-f552-42ac-aa6e-17bc336029ec', 'checkbox', 'Questions 23–24', NULL, '<p>Choose <strong>TWO </strong>correct answers.<br />Which <strong>TWO </strong>points did students most frequently make about music practice?</p>
', 'multiple_choice_many', 'null', '[{"option": "They prefer to practise alone.", "correct": false}, {"option": "They try to practise every day.", "correct": false}, {"option": "They are motivated to practise by fear.", "correct": true}, {"option": "They feel they don’t do enough practice.", "correct": false}, {"option": "They enjoy the challenge of a difficult piece.", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('601e052a-934e-419b-8d08-a7235b5c6a0b', '7da8f4fd-f552-42ac-aa6e-17bc336029ec', 'checkbox', 'Questions 25–26', NULL, '<p>Choose <strong>TWO </strong>correct answers.<br />
Which <strong>TWO </strong>points were most frequently made by students about the pieces they select for assessed performances?</p>
', 'multiple_choice_many', 'null', '[{"option": "They like to hear others performing the same pieces.", "correct": true}, {"option": "They like to choose little-known pieces.", "correct": false}, {"option": "They like to play pieces from memory.", "correct": true}, {"option": "They like their tutor to choose their pieces.", "correct": false}, {"option": "They like to choose technically demanding pieces.", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('d24ef17e-38e2-4384-b9ca-01c27dbdc9bf', '7da8f4fd-f552-42ac-aa6e-17bc336029ec', 'matching', 'Questions 27–30', NULL, '<p>Which comment did most students make about each of the following aspects of performance?</p>
<p>Choose <strong>FOUR </strong>correct answers, <strong>A-G</strong>, next to questions <strong>27-30</strong>.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Aspects of performance</strong></p>\r\n<p>Performing solo {B This is difficult but enjoyable.}</p>\r\n<p>Deciding which pieces to perform {E This is time-consuming.}</p>\r\n<p>Performing with musicians from a different genre {G This happens infrequently.}</p>\r\n<p>Performing with musicians who play the same instrument {A This is very beneficial.}</p>", "answerOptions": [{"optionText": "A This is very beneficial."}, {"optionText": "B This is difficult but enjoyable."}, {"optionText": "C This can affect relationships."}, {"optionText": "D This makes them very nervous."}, {"optionText": "E This is time-consuming."}, {"optionText": "F This is easy."}, {"optionText": "G This happens infrequently."}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 3);
INSERT INTO public.questions VALUES ('97d5112b-492b-464e-a13b-17b4ee3887bb', 'cf4f5acb-c043-4840-8b74-1743cd4a3053', 'checkbox', 'Questions 11 and 12', '<p data-start="91" data-end="119"><strong data-start="91" data-end="119">Choose TWO letters, A–E.</strong></p>
<p data-start="121" data-end="490"><strong data-start="121" data-end="131">11–12.</strong> Which TWO things does the speaker say about visiting the football stadium with children?</p>
', '<p>Choose <strong>TWO</strong> correct answers.</p>
', 'multiple_choice_many', NULL, '[{"option": "A. Children can get their photo taken with a football player.", "correct": false}, {"option": "B. There is a competition for children today.", "correct": true}, {"option": "C. Parents must stay with their children at all times.", "correct": true}, {"option": "D. Children will need sunhats and drinks.", "correct": false}, {"option": "E. The café has a special offer on meals for children.", "correct": false}]', '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1. Thông tin Hướng dẫn cho Khách thăm (Questions 11–14)<br /> </p>\n<p>GUIDE: Good morning and welcome to City Football Club. I&#8217;d like to give you some useful information about your visit to the stadium today and then we&#8217;ll start the tour of the areas of the stadium that are open to visitors.</p>\n<p>I can see lots of children here today, so just to let mums and dads know a few things before we start. The stadium has lots of stairs and the players&#8217; tunnel is very dark. Please don&#8217;t let your children wander off on their own, even for a minute. We don&#8217;t want any accidents or anyone getting frightened.</p>\n<p>Cameras are permitted everywhere and you can take pictures of your child shooting a penalty. (Question 11: permitted) Assistants are helping to organise this and hopefully the queue won&#8217;t be too long.</p>\n<p>It&#8217;s very hot and sunny out on the pitch today. You can get food and drink at the cafe and I really recommend the healthy lunchboxes for children. (Question 12: lunchboxes)</p>\n<p>Also in the cafe, children are invited to do a football-themed drawing. We&#8217;ll pick the best one at the end of the afternoon, so don&#8217;t forget to put your name and contact details on the back. (Question 13: contact details) That way, if you&#8217;ve left the stadium before then, we&#8217;ll send your prize, but sadly we can&#8217;t return drawings.</p>\n<p>I&#8217;d like to mention some features of the tour. We&#8217;ll start with the 360 cinema experience, which has been very popular over the years, and then I&#8217;ll take you to the players&#8217; dressing rooms, before going outside to the seating area and the pitch. (Question 14: cinema)</p>\n<p>I should say, if you&#8217;d prefer your visit to be self-guided, please collect headphones from the reception and then you can listen to the pre-recorded information at your own speed. We&#8217;ve only just introduced this feature and would appreciate your feedback. We&#8217;re thinking of offering tours in other languages in future, so if you have any thoughts on that, we&#8217;d welcome those too.</p>\n<p>If you plan to return another time, you might like to book one of our VIP tours. We&#8217;ve only just started offering these and they can be booked online.</p>\n<p> <br /> </p>\n<p>2. Lịch sử Câu lạc bộ và Bóng đá (Questions 15–20)<br /> </p>\n<p>GUIDE: Now, the stadium you see today was built in 1989, as part of a three-year redevelopment project. While that project was going on, the team had to play its matches at the ground of another club. Apart from that, the club has been here on this site since 1870.</p>\n<p>As some of you may know, that was the start of a really important decade in the history of football in this country. For example, 1870 was also the year that football teams started to include a player whose role it was to guard the goal. (Question 15: goal) It&#8217;s hard to imagine what the game must have been like without someone in that position, isn&#8217;t it?</p>\n<p>In 1872 and 1873, many other clubs were established, both here and abroad. And the following year, in 1874, referees were allowed to send players off if they committed certain offences. And also in that year, teams started having to swap ends at half-time. (Question 16: swap ends)</p>\n<p>One fact I was interested to discover was that in early football games, the aim was for the scorer to get the ball between two flag posts and later between sticks joined at the top with a piece of tape. In 1875, that tape was replaced with the solid crossbar that we&#8217;re familiar with today. (Question 17: crossbar)</p>\n<p>1877 saw the founding of further new clubs, and the history books tell us that in the same year, all the clubs decided to set a limit of 90 minutes for each match. (Question 18: 90 minutes) Before that, it was a more casual arrangement, and this sometimes caused huge arguments and sometimes fights during matches when one team called the end of the game and the other team wanted to play on to try and score a winning goal.</p>\n<p>By 1878, the number of teams in the football league increased again. In addition, referees started using whistles and electric lamps were installed on certain pitches. (Question 19: whistles) This was a significant change, as games could then be played in the evenings all year round.</p>\n<p>In 1880, clubs began to charge fans for admission to games, even though players were still amateurs and had other proper jobs. (Question 20: charge fans) That&#8217;s hard to imagine in the modern professional game, where top players earn significant sums of money from both playing and commercial activities.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('1c879dfa-5291-444d-8477-c9abf5472f0d', 'cf4f5acb-c043-4840-8b74-1743cd4a3053', 'checkbox', 'Questions 13 and 14', '<p data-start="527" data-end="555"><strong data-start="527" data-end="555">Choose TWO letters, A–E.</strong></p>
<p data-start="557" data-end="737"><strong data-start="557" data-end="567">13–14.</strong> Which TWO features of the stadium tour are new this year?</p>
', '<p>Choose <strong>TWO</strong> correct answers.</p>
', 'multiple_choice_many', NULL, '[{"option": "A. VIP tour", "correct": true}, {"option": "B. 360 cinema experience", "correct": false}, {"option": "C. audio guide", "correct": true}, {"option": "D. dressing room tour", "correct": false}, {"option": "E. tours in other languages", "correct": false}]', '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('633316be-f525-4883-aaf1-205e7e27b30a', 'a2b2f0da-439e-41ce-aa15-ffeef4ad940a', 'matching', 'Questions 27–30', '', '<p>What is the main physical benefit of each of the following walking situations?</p>
<p>Choose <strong>FOUR</strong> correct answers, <strong>A-G</strong>, next to questions <strong>27-30</strong>.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Walking situations</strong></p>\n<p>walking with thin-soled footwear {F stronger bones}</p>\n<p>walking in the mountains {C better eyesight}</p>\n<p>walking for the elderly {E regulate sleeping pattern}</p>\n<p>walking long distances {B greater stamina}</p>", "answerOptions": [{"optionText": "A improve balance"}, {"optionText": "B greater stamina"}, {"optionText": "C better eyesight"}, {"optionText": "D lower blood pressure"}, {"optionText": "E regulate sleeping pattern"}, {"optionText": "F stronger bones"}, {"optionText": "G weight reduction"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('11d8f4d7-3bb2-48f7-9d5e-0b49869a80e4', '0b52d227-9178-48ac-985c-e13b7bb2dcbf', 'matrix', 'Questions 34–37', NULL, '<p>Classify the following statements as referring to</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "The study focused on participants’ short-term reaction to receiving flowers.", "correctCategoryLetter": "A"}, {"itemText": "Participants were deliberately misled as to the aim of the study.", "correctCategoryLetter": "A"}, {"itemText": "Receiving flowers had a notable effect on participants’ mental capacities.", "correctCategoryLetter": "C"}, {"itemText": "Male and female responses were more uniform than expected.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "the first study", "categoryLetter": "A"}, {"categoryText": "the second study", "categoryLetter": "B"}, {"categoryText": "the third study", "categoryLetter": "C"}]}', '[{"content": "<p><strong>34. The study focused on participants’ short-term reaction to receiving flowers.</strong></p>\n<ul data-path-to-node=\"23\">\n<li><strong>Đáp án:</strong> <strong>A (the first study)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) Nghiên cứu đầu tiên tập trung vào việc đánh giá tâm trạng tức thì (<em>“immediate emotional expression”</em>) sau khi nhận quà và xem xét hiệu quả kéo dài (<em>“effect lasted for several days”</em>).</li>\n</ul>\n<p><strong>35. Participants were deliberately misled as to the aim of the study.</strong></p>\n<ul data-path-to-node=\"25\">\n<li><strong>Đáp án:</strong> <strong>A (the first study)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “The women were unaware that the study was about the effect of the flowers on their emotions. <strong>They were told that it was a study about their daily moods</strong>…”</li>\n<li><strong>Giải thích:</strong> Đối tượng được thông báo sai về mục đích nghiên cứu (misled).</li>\n</ul>\n<p><strong>36. Receiving flowers had a notable effect on participants’ mental capacities.</strong></p>\n<ul data-path-to-node=\"27\">\n<li><strong>Đáp án:</strong> <strong>C (the third study)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “The researchers found not only a profound elevation of mood, but also <strong>reliable improvements in other measures of cognitive function, like memory</strong>.”</li>\n<li><strong>Giải thích:</strong> Cải thiện chức năng nhận thức (cognitive function/mental capacities) là kết quả của nghiên cứu thứ ba.</li>\n</ul>\n<p><strong>37. Male and female responses were more uniform than expected.</strong></p>\n<ul data-path-to-node=\"29\">\n<li><strong>Đáp án:</strong> <strong>B (the second study)</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “Contrary to predictions regarding <strong>gender differences, both men and women</strong> presented with flowers were <strong>more likely to smile, to stand closer and to initiate conversation</strong>.”</li>\n<li><strong>Giải thích:</strong> Nghiên cứu thứ hai (trong thang máy) quan sát thấy phản ứng của nam và nữ đồng nhất hơn dự đoán.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('bd4bc13a-28e0-4ef0-b2af-d864d0a5be5b', '0b52d227-9178-48ac-985c-e13b7bb2dcbf', 'fillup', 'Questions 38–40', '<p>Complete the summary of paragraph E below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from paragraph E for each answer.</p>
<p style="text-align: center;"><strong>A possible explanation for the appeal of flowers</strong></p>
<p>It has been suggested that our intense response to flowers originates in prehistoric times. The presence of flowers might indicate a potential source of {Food} in a particular location, and primitive humans would search for such signs when looking for a suitable site to raise their {Children}. The interpretation of these signs was essential for the survival of our ancestors. However, the problem with this idea is that the plants producing the most attractive flowers do not usually have fruit which is {Edible}.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>38. It has been suggested that our intense response to flowers originates in prehistoric times. The presence of flowers might indicate a potential source of Food in a particular location…</strong></p>\n<ul data-path-to-node=\"34\">\n<li><strong>Đáp án:</strong> <strong>Food</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “…for early man, finding them in a particular location predicted <strong>future food supplies</strong>…”</li>\n<li><strong>Giải thích:</strong> Việc tìm thấy hoa có thể báo hiệu nguồn cung cấp thức ăn (food) trong tương lai.</li>\n</ul>\n<p><strong>39. …and primitive humans would search for such signs when looking for a suitable site to raise their Children.</strong></p>\n<ul data-path-to-node=\"36\">\n<li><strong>Đáp án:</strong> <strong>Children</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “…predicted future food supplies and possibly a better place to rear <strong>children</strong>.”</li>\n<li><strong>Giải thích:</strong> Hoa cũng có thể báo hiệu một nơi tốt hơn để nuôi dạy con cái (children).</li>\n</ul>\n<p><strong>40. However, the problem with this idea is that the plants producing the most attractive flowers do not usually have fruit which is Edible.</strong></p>\n<ul data-path-to-node=\"38\">\n<li><strong>Đáp án:</strong> <strong>Edible</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “…the showy flowers which humans seem to find most visually attractive are generally found on those plants which yield no <strong>edible</strong> products.”</li>\n<li><strong>Giải thích:</strong> Sai sót của giả thuyết là hoa hấp dẫn nhất lại không cho ra sản phẩm ăn được (edible).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('07961a86-0593-4036-ae13-34a531459dc8', '47b99efa-22f0-40a8-97f6-c7890d0324e6', 'checkbox', 'Questions 23 and 24', '<p>Choose TWO letters, A–E.</p>
<p>23–24. For children with dyspraxia, which TWO problems with handwriting do the students think are easiest to correct?</p>
', '<p>Choose <strong>TWO</strong> correct answers.</p>
', 'multiple_choice_many', NULL, '[{"option": "A. not spacing letters correctly", "correct": true}, {"option": "B. not writing in a straight line", "correct": false}, {"option": "C. applying too much pressure when writing", "correct": true}, {"option": "D. confusing letter shapes", "correct": false}, {"option": "E. writing very slowly", "correct": false}]', '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('ae142e19-346f-4ff0-a29a-a554119f2a5a', 'ec614f7c-36a8-4ab2-987e-2c3068c4f589', 'radio', 'Questions 21–26', '', '<p data-start="46" data-end="83">Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>
