<p dir="ltr"> </p>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">8. camouflage — {Provides camouflage when standing near trees}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“The coat has dark patches separated by light hair, which serves as camouflage, allowing them to blend in with the light and shade patterns of the acacia trees...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lớp lông của hươu cao cổ đóng vai trò như là sự ngụy trang (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"72\">camouflage</strong>), giúp chúng hòa mình vào hoa văn sáng tối của cây keo nhằm ẩn nấp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">9. hands — {Can be used like hands to get leaves}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“In addition, a giraffe''s extraordinary mouth has lips and tongue that can together grasp a branch and then pluck away the leaves while avoiding thorns, almost as humans would grab with their hands.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bộ phận môi và lưỡi của hươu cao cổ có thể cùng nhau phối hợp để bứt lá giống như con người cầm nắm bằng đôi tay (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"126\">hands</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">10. birth — {Length develops in childhood to provide an easier birth for mothers}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"25,0,0\" data-index-in-node=\"26\">“The growth of the neck largely takes place during early childhood, as giraffe mothers would have a difficult time giving birth to young with longer necks.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự phát triển chiều dài cổ diễn ra ở giai đoạn thơ ấu vì nếu con non sinh ra có cổ quá dài, hươu mẹ sẽ gặp khó khăn trong quá trình sinh đẻ (<strong data-path-to-node=\"25,1,0\" data-index-in-node=\"153\">birth / giving birth</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">11. veins — {Extra strong veins keep blood from spilling into other tissue}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"27,0,0\" data-index-in-node=\"26\">“The outside of a giraffe''s veins are extremely thick, to prevent blood leaking into surrounding tissue.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thành bên ngoài của các tĩnh mạch (<strong data-path-to-node=\"27,1,0\" data-index-in-node=\"47\">veins</strong>) rất dày giúp ngăn chặn máu bị rò rỉ/tràn vào các mô xung quanh (<em data-path-to-node=\"27,1,0\" data-index-in-node=\"118\">keep blood from spilling / prevent blood leaking into surrounding tissue</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">12. heart — {heart: Normal size for such a large animal}</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\">“Researchers were also surprised to find that a giraffe does not have an unusually large heart.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cột đặc điểm đang nói về một bộ phận cơ thể có kích thước bình thường chứ không to bất thường. Bài đọc chỉ ra bộ phận gây bất ngờ vì không hề lớn bất thường chính là trái tim (<strong data-path-to-node=\"29,1,0\" data-index-in-node=\"188\">heart</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">13. signals — {Slower reaction time because signals need to go farther to the brain}</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“This is because signals from the nerves travel at about the same speed in giraffes as in rats or other mammals. Given the greater distance they have to travel in the giraffe to reach the brain...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thời gian phản ứng của hươu cao cổ bị chậm đi là do các tín hiệu (<strong data-path-to-node=\"31,1,0\" data-index-in-node=\"78\">signals</strong>) từ dây thần kinh phải di chuyển một quãng đường dài hơn nhiều để đến được não bộ.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('078d375e-6324-47e2-9883-b82f6c451e4f', '77b2d76e-80d1-4bc3-8243-c8d4ed26476c', 'matrix', 'Questions 14 - 17', '', '<p>Write the correct letter, <strong>A-F</strong>, in boxes 14-17 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "an explanation of how water is distributed to plants in the right quantities", "correctCategoryLetter": "C"}, {"itemText": "some examples of current expressions used by Canterbury farmers", "correctCategoryLetter": "A"}, {"itemText": "an argument for increased regulation of agriculture in Canterbury", "correctCategoryLetter": "D"}, {"itemText": "a reference to an agricultural advantage Canterbury has over another part of the world", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. An explanation of how water is distributed to plants in the right quantities — {C}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“The crucial piece of equipment… has become the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"61\">high-tech mechanical irrigation system</strong>. <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"101\">Soil moisture monitors</strong> in the earth beneath each irrigation station <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"169\">signal exactly when</strong> they need to turn the water pumps on.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C mô tả hệ thống tưới tiêu cơ giới hóa cao. Việc sử dụng các thiết bị đo độ ẩm đất (soil moisture monitors) giúp báo hiệu chính xác (signal exactly when) lượng nước cần thiết, đảm bảo nước được phân phối đúng khối lượng mà cây/cỏ cần.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Some examples of current expressions used by Canterbury farmers — {A}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Today it is <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"24\">terms such as ‘mechanisation’ ‘intensification’ and ‘conversion’</strong> that you’ll hear on a typical farm.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Expressions” chính là các “terms” (thuật ngữ/cụm từ). Đoạn A liệt kê các từ mà bạn sẽ nghe thấy trên một nông trại điển hình ở Canterbury ngày nay như: cơ giới hóa, thâm canh và chuyển đổi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. An argument for increased regulation of agriculture in Canterbury — {D}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“Murray Rogers… insists that the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"46\">only long-term solution is for local government to take control of how much water farmers may take</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Increased regulation” (tăng cường quy định/kiểm soát) tương ứng với việc chính quyền địa phương nắm quyền kiểm soát (government to take control) lượng nước nông dân được phép sử dụng. Murray Rogers cho rằng đây là giải pháp duy nhất để cứu các dòng sông.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. A reference to an agricultural advantage Canterbury has over another part of the world — {B}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“One reason is that the big seed companies located in areas of the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"78\">Northern Hemisphere</strong> want to diversify, and because <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"129\">Canterbury is in the Southern Hemisphere, we can grow crops out of season</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lợi thế nông nghiệp (advantage) ở đây là vị trí địa lý ở Nam Bán Cầu, giúp Canterbury có thể trồng cây trái vụ (out of season) so với các công ty ở Bắc Bán Cầu.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('05f74358-e8b5-4e22-b4b9-c7193647ff2a', 'f6a0c121-1148-4d42-aa96-35ee338c7f47', 'matching', 'Questions 26-30', '', '<p>What problems with the following aspects of the proposed interviews do the speakers identify?</p>
<p>Choose <strong>FIVE </strong>answers from the box and write the correct letter, A-H, next to questions 26-30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 12pt;\"><strong>Problems</strong></span></p>\n<p> </p>\n<p>Questions drafted {too complicated}</p>\n<p> </p>\n<p>Time allotted {too long}</p>\n<p> </p>\n<p>Recording equipment used {too unreliable}</p>\n<p> </p>\n<p>Subjects chosen {too vague}</p>\n<p> </p>\n<p>Proposed report {too factual}</p>", "answerOptions": [{"optionText": "too unreliable"}, {"optionText": "too short"}, {"optionText": "too noisy"}, {"optionText": "too long"}, {"optionText": "too formal"}, {"optionText": "too factual"}, {"optionText": "too complicated"}, {"optionText": "too vague"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('dc5b10e4-a47f-4042-9384-b6acb8f9de55', '1c4126b5-d544-47fa-a01e-a2cef4b46daa', 'matching', 'Questions 14-19', NULL, '<p>Choose the correct heading for each section from the list of headings below.</p>
', 'matching_features', '[{"correct": null, "options": [{"content": null}], "question": null}]', '[{"option": "i", "correct": false}, {"option": "ii", "correct": false}, {"option": "iii", "correct": false}]', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": " i Tried and tested solutions"}, {"optionText": "ii Cooperation beneath the waves"}, {"optionText": "iii Working to lessen the problems"}, {"optionText": "iv Disagreement about the accuracy of a certain phrase"}, {"optionText": "v Two clear educational goals"}, {"optionText": "vi Promoting hope"}, {"optionText": "vii A warning of further trouble ahead"}], "matchingItems": null}', '{"layoutType": "standard", "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>14. v (Two clear educational goals)<br />(Đoạn mở: “We want to show people how wonderful they are… However, we also want to highlight the research and conservation efforts…”)<br />→ Mục tiêu của London Zoo gồm hai hướng giáo dục rõ ràng: giúp công chúng chiêm ngưỡng vẻ đẹp của san hô và hiểu được nỗ lực bảo tồn chúng. → v.</p>\n<p> <br />15. ii (Cooperation beneath the waves)<br />(Đoạn 2: “Corals are composed of tiny animals… with tentacles… from algae that live within them… This comfortable symbiotic relationship…”)<br />→ Giải thích mối quan hệ cộng sinh (cooperation) giữa san hô và tảo – cả hai cùng có lợi. → ii.</p>\n<p> <br />16. iv (Disagreement about the accuracy of a certain phrase)<br />(Đoạn 3: “Coral reefs are often described as the ‘rainforests of the sea’, though the comparison is dismissed by some naturalists, including David Attenborough.”)<br />→ Có sự bất đồng về việc dùng cụm từ “rainforests of the sea”, Attenborough không đồng ý. → iv.</p>\n<p> <br />17. vii (A warning of further trouble ahead)<br />(Đoạn 4: “Unfortunately… rising ocean temperatures… bleaching events… scientists advise that more than 90% of reefs could be lost by 2050.”)<br />→ Đưa ra cảnh báo nghiêm trọng về tương lai của san hô, khi chúng đang chết hàng loạt. → vii.</p>\n<p> <br />18. iii (Working to lessen the problems)<br />(Đoạn 5: “Scientists are trying to pinpoint hardy types of coral that could survive our overheated oceans… research has enabled some corals to spawn artificially…”)<br />→ Trình bày nỗ lực nghiên cứu để giảm thiểu thiệt hại và phục hồi san hô. → iii.</p>\n<p> <br />19. vi (Promoting hope)<br />(Đoạn 6: “The crucial point is that the progress we make… can be shown to the public and encourage them to believe that we can do something to save the reefs.”)<br />→ Kết bài mang thông điệp truyền hy vọng – rằng vẫn có thể cứu được san hô. → vi.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('dd052d83-c7c0-4e7c-b264-d16fcd3e15be', '00e21c10-e901-465d-b799-195b66e50d61', 'radio', 'Questions 27–31', NULL, '<p>Choose the correct answer.</p>
', 'multiple-choice', '[{"correct": 2, "options": [{"content": "the universality of Piaget’s insights into the workings of the mind."}, {"content": "the similarity between children’s thought processing in different cultures."}, {"content": "how Piaget’s work represents a crucial turning-point in our approach to education."}, {"content": "how Piaget’s work has aided our understanding of man’s evolution from primitive origins."}], "question": "In the second paragraph the writer mentions the example of modern anthropology to illustrate"}, {"correct": 0, "options": [{"content": "The factual accuracy of what children say is of minor significance."}, {"content": "Children want to learn about scientific principles."}, {"content": "Children’s reasoning processes can be amusing to adults."}, {"content": "Children often pretend that they know the answers to questions."}], "question": "According to the writer, what point is illustrated by the dialogue about the wind?"}, {"correct": 3, "options": [{"content": "preventing children from making false assumptions."}, {"content": "giving children honest feedback on their hypotheses."}, {"content": "showing children how to formulate their own ideas about the world."}, {"content": "maintaining children’s confidence in their ability to interpret the world."}], "question": "Piaget believed in the importance of"}, {"correct": 2, "options": [{"content": "Children’s sense of their surroundings changes as they get older."}, {"content": "Children are able to grasp certain complex ideas as well as adults are."}, {"content": "Even apparently irrational ideas can be worthy of interest."}, {"content": "Sometimes the simplest explanations are the best."}], "question": "What does the writer suggest in the seventh paragraph?"}, {"correct": 2, "options": [{"content": "outline Piaget’s contribution to a range of scientific fields."}, {"content": "summarise how education has benefited from Piaget’s finding."}, {"content": "discuss Piaget’s role in the development of 20th-century psychology."}, {"content": "express doubts about a number of Piaget’s theories."}], "question": "The writer’s main purpose is to"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\">27. In the second paragraph the writer mentions the example of modern anthropology to illustrate</h3>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>C. how Piaget’s work represents a crucial turning-point in our approach to education.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “It was a shift <strong>comparable</strong> to the way modern anthropology displaced stories of primitive tribes being ‘noble savages’ and ‘cannibals’.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Tác giả so sánh sự thay đổi trong cách nhìn nhận trẻ em của Piaget với sự thay đổi lớn trong nhân học hiện đại (từ quan niệm sai lầm sang sự thật). Điều này cho thấy công trình của Piaget đã tạo ra một <strong>bước ngoặt quan trọng</strong> (<em>crucial turning-point</em>) trong cách chúng ta tiếp cận giáo dục.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">28. According to the writer, what point is illustrated by the dialogue about the wind?</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>A. The factual accuracy of what children say is of minor significance.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “Piaget recognized that five-year-old Julia’s beliefs, while not correct by any adult criterion, are not ‘incorrect’ either. <strong>Classifying them as ‘true’ or ‘false’ misses the point</strong> and shows a lack of respect for the child.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Piaget nhấn mạnh rằng việc phân loại ý kiến của trẻ em là “đúng” hay “sai” (<em>factual accuracy</em>) là <strong>bỏ sót vấn đề</strong> (<em>misses the point</em>), tức là độ chính xác thực tế chỉ mang ý nghĩa thứ yếu (<em>minor significance</em>) so với quá trình tư duy của trẻ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"4\">29. Piaget believed in the importance of</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>D. maintaining children’s confidence in their ability to interpret the world.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “But his work strongly suggests that automatic reaction of putting the child right may well be <strong>counter-productive</strong>. If their theories are always greeted by ‘Nice try, but this is how it really is…’ <strong>they might give up after a while on making theories</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Piaget cảnh báo rằng việc sửa lỗi ngay lập tức (<em>putting the child right</em>) có thể gây phản tác dụng (<em>counter-productive</em>) và khiến trẻ em từ bỏ việc tạo ra các lý thuyết của riêng mình (<em>give up after a while on making theories</em>). Điều này ngụ ý rằng điều quan trọng là phải duy trì <strong>sự tự tin</strong> (<em>maintaining children’s confidence</em>) của trẻ em trong khả năng tự diễn giải (<em>interpret</em>) thế giới của chúng.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">30. What does the writer suggest in the seventh paragraph?</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>C. Even apparently irrational ideas can be worthy of interest.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) Tác giả đề cập đến những “định luật vật lý sơ khai” của trẻ em như: “thấy sao bắt vậy” (mặt trăng, mặt trời đi theo mình), và việc trẻ em “khăng khăng rằng đi nhanh hơn có thể tốn nhiều thời gian hơn”. Einstein đã bị <strong>hấp dẫn</strong> (<em>intrigued</em>) bởi những phát hiện này vì chúng <strong>trái ngược với lẽ thường</strong> (<em>contrary to common sense</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Việc Einstein bị hấp dẫn bởi những ý tưởng <em>tưởng chừng phi lý</em> (<em>apparently irrational</em>) đó cho thấy những ý tưởng này <strong>xứng đáng được quan tâm</strong> (<em>worthy of interest</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"15\">31. The writer’s main purpose is to</h3>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong>Đáp án:</strong> <strong>C. discuss Piaget’s role in the development of 20th-century psychology.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong>Dẫn chứng:</strong> (Toàn bộ bài đọc) Bài đọc tập trung vào việc mô tả công việc, các lý thuyết mang tính <strong>nền tảng</strong> của Piaget (“provided the foundation for today’s education-reform movements” [Đoạn 2]), tầm ảnh hưởng <strong>lâu dài</strong> của ông đối với tâm lý học (“influence on psychology may be longer lasting” [Đoạn 3]), và cách ông biến nhận thức luận thành một <strong>khoa học</strong> (<em>“made it a science”</em>) [Đoạn 8].</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong>Giải thích:</strong> Mục đích chính là làm nổi bật <strong>vai trò trung tâm và tầm ảnh hưởng</strong> của Piaget đối với sự phát triển của lĩnh vực tâm lý học nhận thức trong thế kỷ 20.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('5ef3f478-8f3e-4e75-838e-946f85fa3f04', '00e21c10-e901-465d-b799-195b66e50d61', 'matching', 'Questions 32–36', NULL, '<p>Complete the summary using the list of words, <strong>A-I</strong>, below.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p>Piaget maintained that children’s mental processes were far more {G logical} than they might appear. He encouraged the view that a child was not a ‘blank slate’ waiting to be filled with information, but rather a systematic builder of knowledge who regularly tries out his or her own {B theories} about the world.</p>\n<p>Piaget’s impact on the area of {F psychology} could well outlast that of more celebrated pioneers of this discipline. Despite doubts cast over his ideas by the current view associating knowledge exclusively with the {C brain} , the effects of his work are still strong today. His principles are still widely used in the professional development of {E teachers} .</p>", "answerOptions": [{"optionText": "A correct"}, {"optionText": "B theories"}, {"optionText": "C brain"}, {"optionText": "D simple"}, {"optionText": "E teachers"}, {"optionText": "F psychology"}, {"optionText": "G logical"}, {"optionText": "H thought"}, {"optionText": "I philosophers"}], "matchingItems": null}', 'null', '[{"content": "<h3 data-path-to-node=\"4\">32. Piaget maintained that children’s mental processes were far more <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>G. logical</strong> than they might appear.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>G. logical</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) “…behind their cute and seemingly irrational utterances were thought processes that had their own kind of order and their own special <strong>logic</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Piaget nhận thấy quá trình tư duy của trẻ em có trật tự và <strong>logic</strong> (<em>logical</em>) riêng, khác biệt so với người lớn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"7\">33. He encouraged the view that a child was not a ‘blank slate’ waiting to be filled with information, but rather a systematic builder of knowledge who regularly tries out his or her own <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>B. theories</strong> about the world.</h3>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>B. theories</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “…but active builders of knowledge – little scientists who are constantly creating and testing their own <strong>hypotheses</strong> about the world.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Trẻ em là những nhà khoa học nhỏ bé, liên tục tạo ra và kiểm tra <strong>giả thuyết</strong> (<em>hypotheses</em>) của riêng mình, đồng nghĩa với <strong>lý thuyết</strong> (<em>theories</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">34. Piaget’s impact on the area of <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>F. psychology</strong> could well outlast that of more celebrated pioneers of this discipline.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>F. psychology</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “And though he may not be as famous as Sigmund Freud or even B F Skinner, his influence on <strong>psychology</strong> may be longer lasting.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Ảnh hưởng của Piaget trong lĩnh vực <strong>tâm lý học</strong> (<em>psychology</em>) có thể lâu dài hơn các nhà tiên phong khác.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">35. Despite doubts cast over his ideas by the current view associating knowledge exclusively with the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>C. brain</strong>, the effects of his work are still strong today.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>C. brain</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) “In the past decade, Piaget has been vigorously challenged by the current fashion of viewing knowledge as an intrinsic property of the <strong>brain</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Công trình của Piaget bị thách thức bởi quan điểm hiện tại cho rằng kiến thức là một thuộc tính cố hữu của <strong>bộ não</strong> (<em>brain</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">36. His principles are still widely used in the professional development of <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>E. teachers</strong>.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>E. teachers</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “He has been revered by generations of <strong>teachers</strong> inspired by the belief that children are not empty vessels…” (Đoạn 8) “Although every <strong>teacher</strong> in training still memorises Piaget’s successive stages of childhood development…”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Các nguyên tắc của ông vẫn được sử dụng rộng rãi trong quá trình đào tạo và phát triển nghề nghiệp của <strong>giáo viên</strong> (<em>teachers</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('77b95595-a43b-4e81-bba2-c27e494aed43', '00e21c10-e901-465d-b799-195b66e50d61', 'radio', 'Questions 37–40', NULL, '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, choose <strong>NO</strong> if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Piaget’s early work in Paris involved innovative research techniques."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Piaget gave clear guidelines as to how adults should give information to children."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Piaget made a significant contribution to the field of epistemology."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "We still have much to learn about the nature of knowledge."}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\">37. Piaget’s early work in Paris involved innovative research techniques.</h3>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “In 1920, while doing research in a child-psychology laborartory in Paris, Piaget noticed that children of the same age made similar errors on intelligence tests.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Bài đọc chỉ đề cập đến việc Piaget làm nghiên cứu ở Paris và <strong>nhận thấy</strong> (<em>noticed</em>) những sai sót tương tự của trẻ em trong các bài kiểm tra trí thông minh. <strong>Không có thông tin</strong> nào mô tả liệu những kỹ thuật nghiên cứu (<em>research techniques</em>) mà ông sử dụng lúc đó có phải là <strong>đổi mới</strong> (<em>innovative</em>) hay không.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">38. Piaget gave clear guidelines as to how adults should give information to children.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “<strong>Piaget was not an educator and never laid down rules about how to intervene in such situations.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Bài đọc khẳng định Piaget <strong>không phải là nhà giáo dục và chưa bao giờ đặt ra các quy tắc</strong> (<em>never laid down rules</em>) về cách người lớn nên can thiệp hoặc truyền đạt thông tin cho trẻ em. Điều này mâu thuẫn trực tiếp với nhận định rằng ông đã đưa ra các <strong>hướng dẫn rõ ràng</strong> (<em>clear guidelines</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"9\">39. Piaget made a significant contribution to the field of epistemology.</h3>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “His real interest was <strong>epistemology</strong> – the theory of knowledge – which, like physics, was considered of a branch of philosophy until <strong>Piaget came along and made it a science</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Piaget đã biến kiến thức luận (<em>epistemology</em>) từ một nhánh của triết học thành một <strong>khoa học</strong> (<em>made it a science</em>). Việc thay đổi bản chất của một lĩnh vực nghiên cứu từ triết học sang khoa học được coi là một <strong>đóng góp đáng kể</strong> (<em>significant contribution</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">40. We still have much to learn about the nature of knowledge.</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) “…the difference between what the baby brings and what the adult has is so immense that the new discoveries do not significantly reduce the gap, but <strong>only increase the mystery</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Mặc dù đã có những khám phá mới, sự khác biệt giữa kiến thức sơ khai và kiến thức người lớn vẫn còn quá lớn, đến mức các khám phá mới chỉ <strong>làm tăng thêm sự bí ẩn</strong> (<em>increase the mystery</em>). Điều này ngụ ý rằng chúng ta <strong>còn rất nhiều điều để học</strong> (<em>still have much to learn</em>) về bản chất của kiến thức.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('5268ecd6-9304-4341-ae0c-d1814177c164', '2a652167-fe58-4517-a8e2-1ada73982b30', 'radio', 'Questions 37-40', NULL, '<p>Choose the correct letter, A, B, C or D.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A. It has grown alongside the development of ever more advanced robots."}, {"content": "B. It is the result of our inclination to attribute human characteristics to non-human entities."}, {"content": "C. It has its origins in basic misunderstandings about how inanimate objects function."}, {"content": "D. It demonstrates a key difference between human intelligence and machine intelligence."}], "question": "What point does Richardson make about fear of machines?"}, {"correct": 2, "options": [{"content": "A. robots outnumbering people"}, {"content": "B. robots having abilities which humans do not"}, {"content": "C. artificial intelligence developing independent thought"}, {"content": "D. artificial intelligence taking over every aspect of our lives"}], "question": "What potential advance does Rees see as a cause for concern?"}, {"correct": 1, "options": [{"content": "A. how science fiction influences our attitudes to robots"}, {"content": "B. how fundamental robots are to the science fiction genre"}, {"content": "C. how the image of robots in science fiction has changed over time"}, {"content": "D. how reactions to similar portrayals of robots in science fiction may vary"}], "question": "What does Wolpert emphasise in his response to the question about science fiction?"}, {"correct": 2, "options": [{"content": "A. warning people not to confuse one with the other"}, {"content": "B. outlining ways in which one has impacted on the other"}, {"content": "C. recommending a change of approach in how people view them"}, {"content": "D. explaining why scientists have a different perspective on them from other people"}], "question": "What is Richardson doing in her comment about reality and fantasy?"}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>37. What point does Richardson make about fear of machines? → B<br />(“It has grown alongside the development of ever more advanced robots.”)<br />→ Nỗi sợ tăng dần theo sự phát triển của máy móc hiện đại hơn.</p>\n<p> <br />38. What potential advance does Rees see as a cause for concern? → C<br />(“Computer networks could behave like a single ‘brain’… with goals contrary to human welfare.”)<br />→ Ông lo trí tuệ nhân tạo hợp nhất có thể điều khiển mọi mặt của cuộc sống con người.</p>\n<p> <br />39. What does Wolpert emphasise in his response to the question about science fiction? → B<br />(“Science fiction has often been remarkable at predicting the future.”)<br />→ Ông nhấn mạnh rằng khoa học viễn tưởng thường dự đoán tương lai rất chính xác.</p>\n<p> <br />40. What is Richardson doing in her comment about reality and fantasy? → C<br />(“Scientists and technologists made this separation… we need to bring these understandings together.”)<br />→ Richardson đang khuyến khích thay đổi cách tiếp cận giữa thực tế và tưởng tượng – để con người ít sợ hãi robot hơn.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('d3a053d6-c091-4ecb-9ffe-c79a06555000', '191f773b-adf8-46ad-8ce6-69f2c54f14f3', 'matching', 'Questions 27-30', '', '<p>According to the speakers, what is the main advertising focus of each of the following shampoo advertisements?</p>
<p>Choose <strong>FOUR </strong>answers from the box and write the correct letter, <strong>A-G</strong>, next to questions 27-30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Advertising focuses</strong></p>\n<p> </p>\n<p>Zing {enviable lifestyle}</p>\n<p> </p>\n<p>Splash {romantic interest}</p>\n<p> </p>\n<p>Just go {product reliability}</p>\n<p> </p>\n<p>Brozene  {link to relaxation}</p>", "answerOptions": [{"optionText": "link to relaxation"}, {"optionText": "enviable lifestyle"}, {"optionText": "natural ingredients"}, {"optionText": "masculine image"}, {"optionText": "product reliability"}, {"optionText": "romantic interest"}, {"optionText": "use by celebrities"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('a7208457-12f4-4b44-807c-457f9c368e14', '024323bf-6e54-472e-bb1b-26bc6ec5de0e', 'fillup', 'Question 31-40', '<p data-path-to-node="2">Complete the sentences below.</p>
<p data-path-to-node="2">Write <strong data-path-to-node="2" data-index-in-node="73">ONE WORD ONLY</strong> for each answer.</p>
<p style="text-align: center;" data-path-to-node="3"><span style="font-size: 12pt;"><strong data-path-to-node="3" data-index-in-node="0">The Restoration of Paintings</strong></span></p>
<p data-path-to-node="4"><strong data-path-to-node="4" data-index-in-node="0">Various Damage:</strong></p>
<ul data-path-to-node="5">
<li>
<p>Ripping canvas was caused by over stretching of putting into a {frame}.</p>
</li>
<li>
<p>Brightness changes due to accumulated {dirt} on top of painting.</p>
</li>
<li>
<p>Paint’s color fades when exposed to the light of the {sun}.</p>
</li>
<li>
<p>Method of storage leads to the emerge of {crack} in the paint.</p>
</li>
<li>
<p>Varied {temperature} cause sticky paint.</p>
</li>
</ul>
<p><strong data-path-to-node="6" data-index-in-node="0">Restoration Process:</strong></p>
<ul data-path-to-node="7">
<li>
<p>Restorers applied {wax} on the back of canvas to make it stronger.</p>
</li>
<li>
<p>Tools such as {microscopes} are used to examine the painting completely.</p>
</li>
</ul>
<p><strong data-path-to-node="8" data-index-in-node="0">Cleaning Tools:</strong></p>
<ul data-path-to-node="9">
<li>
<p>Restorers use sponges made from {cotton} to clean the work softly.</p>
</li>
<li>
<p>Old paintings were covered with varnish, {chemicals} cant be used for cleaning.</p>
</li>
<li>
<p>The most common liquid used in cleaning is human {saliva}.</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 4: THE RESTORATION OF PAINTINGS</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Lecturer:</strong> Welcome to today''s lecture about restoration of paintings. We all know that no matter how carefully a painting is stored or handled, it can be damaged. It''s the job of a restorer to fix this damage, but to do so and return the painting to the original appearance, we need to know about the material that the artist used when creating it.</p>\n<p data-path-to-node=\"5\">So, the first stage for a restorer is to determine what kind of paint was applied to what kind of surface. The restoration process also involves determining what kind of damages have been done to the artwork. There are several damages concluded: When the artist is preparing to hang and display a work, he or she has to stretch the canvas to fit it over a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"356\">(Q31) frame</strong></span>, and this can result in the ripping of the canvas. A restorer needs to be able to fix this kind of problem, and hopefully, make preparation from the beginning.</p>\n<p data-path-to-node=\"6\">And another thing is time; this can cause excessive damage to the art over the years. A painting can change from being quite bright to appearing dull. This is often due to the collection of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"190\">(Q32) dirt</strong></span> on the surface of the work. This all needs to be removed, and is almost the most common task restorers perform.</p>\n<p data-path-to-node=\"7\">Another problem with paintings is fading of the colours. If a painting is hung in the wrong place, particularly in the light of the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"132\">(Q33) sun</strong></span>, this fades the paint and its appearance. This happens not just when hanging the painting, but also in storing them. When artists want to store a painting, it''s common for them to roll it up for storage. This process can result in a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"375\">(Q34) crack</strong></span> in the paint. Some artists such as Picasso said he might disagree, but it''s impossible that the paint could cut off from the canvas entirely—something that a short-broke artist wouldn''t like.</p>\n<p data-path-to-node=\"8\">It''s important when we are restoring paintings to consider how they react to things in a new environment. For example, the paint can become sticky. This can be a very serious problem which can be caused by even minimum changes of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"230\">(Q35) temperature</strong></span>. This is something else to watch for.</p>\n<p data-path-to-node=\"9\">A lot of damage to artworks in the past was actually caused by the restorers themselves. Restorers used to try to make the canvas stronger, and they put something onto the work. Part of this process involved putting <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"216\">(Q36) wax</strong></span> on the back of the canvas, but this leaves visible marks on the surface of the paintings. Hopefully, nowadays, with improved scientific knowledge, restoration can avoid making similar errors.</p>\n<p data-path-to-node=\"10\">Restorers have several tools at their disposal. Some are high-tech, others surprisingly low-tech. It''s not that common to see a restorer examine an ink painting to use a certain tool to eliminate the mind-line under the surface of the paint, but it''s important to analyze what kind of paint or materials the artist used. Restorers often use <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"143\">(Q37) microscopes</strong></span> so they can analyze the materials thoroughly.</p>\n<p data-path-to-node=\"11\">For restoration involves cleaning the surface of the painting. Restorers use sponges made from <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"95\">(Q38) cotton</strong></span> to gently clean the work. You might be curious about what is used to clean the paintings. Because some of the very old paintings were covered with varnish, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"264\">(Q39) chemicals</strong></span> cannot be used for cleaning, due to the fact that they can remove or damage the varnish layer.</p>\n<p data-path-to-node=\"12\">But restorers have to use something to clean the paintings. This is where the low-tech tools come in. The most common liquid used in the cleaning is human <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"155\">(Q40) saliva</strong></span>. It does a great job of cleaning the painting and it doesn''t cause damage. Now, let’s start by looking at...</p>"}]', 0);
INSERT INTO public.questions VALUES ('2215d306-11ce-4416-b7f1-893af73612f4', '1309e07e-3d9f-487e-a665-b3c72c540cc1', 'matrix', 'Questions 14–16', NULL, '<p>Reading Passage 2 has six paragraphs, A–F. Which paragraph contains the following information?</p>
<p><strong>NB </strong>You may use any letter more than once.</p>
', 'other', '[{"correct": null, "options": [{"content": null}], "question": null}]', '[{"option": "A", "correct": false}, {"option": "B", "correct": false}, {"option": "C", "correct": false}, {"option": "D", "correct": false}, {"option": "E", "correct": false}, {"option": "F", "correct": false}]', '{"layoutType": "standard", "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "mention of false assumptions about why people procrastinate", "correctCategoryLetter": "B"}, {"itemText": "reference to the realisation that others also procrastinate", "correctCategoryLetter": "F"}, {"itemText": "neurological evidence of a link between procrastination and emotion", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p>14. B<br />(Đoạn B: “Contrary to popular belief, procrastination is not due to laziness or poor time management.”)<br />→ Tác giả đề cập những giả định sai lầm (false assumptions) về lý do con người trì hoãn — cụ thể là nhiều người tưởng do “lười biếng” hoặc “quản lý thời gian kém”, nhưng khoa học cho thấy nguyên nhân thật sự khác.</p>\n<p> <br />15. F<br />(Đoạn F: “We should remind ourselves that we’re not the first person to procrastinate, nor the last.”)<br />→ Tác giả nhắc đến việc nhận ra rằng ai cũng từng trì hoãn, giúp người đọc cảm thấy bớt tự trách và dễ bắt đầu lại hơn.</p>\n<p> <br />16. B<br />(Đoạn B: “Research involving brain imaging has found that areas of the brain linked to detection of threats and emotion regulation are actually different in people who chronically procrastinate…” )<br />→ Có bằng chứng thần kinh học (neurological evidence) cho thấy sự liên hệ giữa trì hoãn và cảm xúc, vì người hay trì hoãn có vùng não xử lý cảm xúc khác biệt.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
