INSERT INTO public.questions VALUES ('a0665d77-4ce7-4a48-b17c-19fa0ce81fc2', 'd9a1b43c-1194-4a6e-a4b4-1c876aaf1069', 'matrix', 'Questions 27-32.', NULL, '<p>Reading Passage 3 has seven paragraphs, A-G.</p>
<p>Which paragraph contains the following information?</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "a description of how a contestant remembers complex sequences", "correctCategoryLetter": "D"}, {"itemText": "an example of how one person’s memory was improved over time", "correctCategoryLetter": "G"}, {"itemText": "a description of a memorizing competition", "correctCategoryLetter": "A"}, {"itemText": "a commonly held belief about memory that many experts say is unproven", "correctCategoryLetter": "E"}, {"itemText": "a reference to the first recorded use of memorizing through location", "correctCategoryLetter": "B"}, {"itemText": "a reference to an unusual condition which results in improved memory", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">27. A description of how a contestant remembers complex sequences: D</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Mô tả về cách một thí sinh ghi nhớ các chuỗi dữ liệu phức tạp.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn D, câu 3: “When Cooke commits a deck to memory, he does it <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"75\">three cards in one go</strong>, with every three-card group forming a <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"136\">composite picture of a person doing something to an object</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn D giải thích kỹ thuật cụ thể (Person-Verb-Object) mà Ed Cooke sử dụng để biến các chuỗi quân bài phức tạp thành những hình ảnh sinh động nhằm ghi nhớ dễ dàng hơn.</p>\n</li>\n</ul>\n<hr data-path-to-node=\"4\" />\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. An example of how one person’s memory was improved over time: G</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một ví dụ về việc trí nhớ của một người đã được cải thiện theo thời gian như thế nào.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn G, câu 2: “During <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"34\">two years of experimentation</strong>, S.V. <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"69\">increased his ability</strong> to recall numbers from seven to <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"123\">over eighty</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn G đưa ra số liệu cụ thể về sự tiến bộ của S.V. sau 2 năm luyện tập, từ việc chỉ nhớ được 7 con số lên đến hơn 80 con số.</p>\n</li>\n</ul>\n<hr data-path-to-node=\"7\" />\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. A description of a memorizing competition: A</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một mô tả về một cuộc thi ghi nhớ.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn A, câu 1 &amp; 4: “The Examinations School at Oxford University is where… <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"88\">34 contestants gathered at the World Memory Championships</strong>… Reciting poems, memorizing digit sequences… are just a few of the tasks that test the limits…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn A thiết lập bối cảnh của cuộc thi Vô địch Trí nhớ Thế giới, mô tả địa điểm tổ chức (Oxford) và các phần thi mà thí sinh phải thực hiện.</p>\n</li>\n</ul>\n<hr data-path-to-node=\"10\" />\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">30. A commonly held belief about memory that many experts say is unproven: E</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một niềm tin phổ biến về trí nhớ mà nhiều chuyên gia nói rằng chưa được chứng minh.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn E, câu 1 &amp; 2: “The term <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"40\">‘photographic memory’</strong> is frequently used… Yet, most researchers agree there is <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"121\">no proof that such a memory truly exists</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn E thảo luận về khái niệm “trí nhớ chụp ảnh” — một điều mà công chúng rất tin tưởng nhưng các nhà khoa học lại khẳng định là không có bằng chứng xác thực (unproven/myth).</p>\n</li>\n</ul>\n<hr data-path-to-node=\"13\" />\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. A reference to the first recorded use of memorizing through location: B</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Đề cập đến lần sử dụng đầu tiên được ghi chép lại về việc ghi nhớ thông qua vị trí.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn B, câu 1: “…loci method, reportedly <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"54\">originating in 477 BC with the Greek poet Simonides of Ceos</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn B xác nhận phương pháp Loci (nhớ bằng vị trí) bắt nguồn từ năm 477 TCN bởi Simonides. Đây là mốc thời gian đầu tiên được ghi nhận.</p>\n</li>\n</ul>\n<hr data-path-to-node=\"16\" />\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">32. A reference to an unusual condition which results in improved memory: F</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Đề cập đến một tình trạng bất thường dẫn đến việc cải thiện trí nhớ.</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn F, câu 2: “Shereshevski also experienced <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"57\">synesthesia</strong>, a rare <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"77\">sensory condition</strong> where the senses are interconnected, which <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"138\">significantly improved his memorization ability</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn F nói về hiện tượng “synesthesia” (chứng cảm giác kèm) — một tình trạng thần kinh hiếm gặp giúp Shereshevski ghi nhớ thông tin một cách cực kỳ sống động và bền vững.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('543d7187-3d71-4309-99b5-495183ece5be', '550c6993-3ef0-4f71-9d5c-7d38a7389ba1', 'fillup', 'Question 26-30', '<p>Complete the notes below.<br />
Write <strong>NO MORE THAN THREE WORDS AND/OR A NUMBER</strong> tor each answer</p>
<p>Presentations should last for {30–40 minutes}</p>
<p>(Plus time for {question|questions|} and {discussion} )</p>
<p>Sources of information<br />
– Bibliography<br />
– Library books<br />
– {Journal}<br />
– {Internet}</p>
<p>For the presentations, use:<br />
– Overahead projector<br />
– Whiteboard<br />
– {Photocopy}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('2d0ca876-34d9-4e4f-9d9d-017977afb35c', 'a2b2f0da-439e-41ce-aa15-ffeef4ad940a', 'radio', 'Questions 21–26', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "she has read it too."}, {"option_text": "what she says reminds him of it."}, {"option_text": "he thinks she might like to do similar research."}], "question": "Daniel mentions the research about walking and creativity to Katie because"}, {"correct": 0, "options": [{"option_text": "sitting"}, {"option_text": "running"}, {"option_text": "listening to music."}], "question": "In the experiments, researchers compared participants’ creativity when walking and when"}, {"correct": 1, "options": [{"option_text": "type of control group."}, {"option_text": "pattern of activities."}, {"option_text": "way of selecting participants."}], "question": "Daniel says that in each experiment, there was a different"}, {"correct": 0, "options": [{"option_text": "biased in favour of certain people"}, {"option_text": "a good indicator of creativity."}, {"option_text": "open to personal interpretation."}], "question": "Daniel thinks the experiment with words is"}, {"correct": 2, "options": [{"option_text": "they are doubtful about its aims."}, {"option_text": "they are confused by its methods."}, {"option_text": "they are cautious about its conclusions."}], "question": "What is Katie and Daniels attitude to the experiment on focused thinking?"}, {"correct": 1, "options": [{"option_text": "whether other types of exercise affect creativity."}, {"option_text": "the cause of the improvement in creativity."}, {"option_text": "how the results can be applied to creativity in real life."}], "question": "Katie thinks that the best way forward is to consider"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Katie:</strong> Hi Daniel!</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Daniel:</strong> Katie, you look as if you’re off somewhere.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Katie:</strong> Yes, I was just heading out for a walk.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Daniel:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"8\">(Q21) Hmm, funny. I was just reading an article about some research that’s been done on the effects of walking on creativity.</strong></span></p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Katie:</strong> Huh, sounds interesting. I’ve always found walking helped me think, but this article confirms that everybody can benefit.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Daniel:</strong> Oh, tell me more.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Katie:</strong> Okay, but I may even do some more research on it at some point, so don’t pinch my idea, promise? Well, in the experiments, the researchers tested participants’ creativity by comparing how many ideas they thought of while they were walking, compared to while they were doing other activities.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Daniel:</strong> What, like listening to music?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Katie:</strong> Nothing like that. <strong data-path-to-node=\"11\" data-index-in-node=\"26\"><span style=\"background-color: #f1c40f;\">(Q22) But they did analyze the ideas participants came up with when sitting both outdoors and inside</span>.</strong> What I found surprising was that they didn’t compare walking to other forms of exercise, like running for example.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Daniel:</strong> Right. So what was the difference between the experiments?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Katie:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"7\">(Q23) Well, in each one, the activities were put together in different ways.</strong></span> Several of the experiments specifically focused on the ability of participants to come up with new ideas. Then the final experiment was a control test of sorts.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Daniel:</strong> Oh, right.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Katie:</strong> In one experiment, participants had to think of unusual uses for three everyday objects within a time limit.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Daniel:</strong> OK, and then there was an experiment with words. What did they ask them to do?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Katie:</strong> Compare words in unusual ways. For example, the word “sweet”. If participants simply said “sweet as sugar”, that wasn’t creative. But an answer like “sweet as a cat with honey on its paws” was okay.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Daniel:</strong> I can see why they’d ask them to do that.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Katie:</strong> Really? I just don’t see how the experiment is fair.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Daniel:</strong> Why?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Katie:</strong> Because the conclusions are based only on the researcher’s opinion.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Daniel:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"22\" data-index-in-node=\"8\">(Q24) I think it’s more that anyone who’d studied language would be at an advantage.</strong></span> Hmm, OK. Was there an experiment about focused thinking?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Katie:</strong> Yeah, there was. It aimed to find out if walking helped focused thinking, though I wasn’t sure that I agreed with their findings. They decided that walking doesn’t help this type of thinking.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Daniel:</strong> What evidence did they have?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Katie:</strong> Well, that’s it. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"24\">(Q25) I don’t think there was enough evidence to support their conclusions, even if their methods were sound.</strong></span></p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Daniel:</strong> Well, I’d certainly hesitate before making such a bold statement. Still, it’s a first step, isn’t it?</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Katie:</strong> I suppose to move forward with this, they’ll need to test other ways people keep fit, like swimming. That would be useful. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"27\" data-index-in-node=\"130\">(Q26) But personally, I’d like to know more about the fundamental reason for the effect on people’s creativity.</strong></span></p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Daniel:</strong> That would be good. Then it could be applied more widely in work, for example.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Katie:</strong> Again, that’s secondary, really.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Daniel:</strong> But how would you test walking if you wanted to assess its physical benefits?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Katie:</strong> Well, firstly, I’d like to know more about the benefits of different situations. What about the effect of footwear?</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Daniel:</strong> Hmm, hadn’t thought of that.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Katie:</strong> Well, I’ve read that shoes with thinner soles were found to be better for people’s joints. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"35\" data-index-in-node=\"98\">(Q27) It even made the skeletal structure tougher.</strong></span></p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Daniel:</strong> Interesting. Was that because they lost weight?</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Katie:</strong> Not as far as I’m aware. And then there’s walking in the mountains.</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Daniel:</strong> Walking in the mountains? Hmm, I think I’ve read something about that. Doesn’t altitude help people regulate their sleep patterns?</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Katie:</strong><span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"39\" data-index-in-node=\"7\">(Q28) It’s more that it improves your vision.</strong></span></p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Daniel:</strong> It must be those breathtaking views.</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Katie:</strong> Yeah. And what about the effect that walking has for elderly people? Better balance, by any chance?</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Daniel:</strong> More than that. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"42\" data-index-in-node=\"24\">(Q29) It had a positive effect by helping them maintain their body clock’s natural rhythm, both when going to bed and waking up.</strong></span></p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Katie:</strong> Right. And what about the effect of walking long distances?</p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Daniel:</strong> Well, a person needs to find the balance between their optimum speed and their natural breathing pattern. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"44\" data-index-in-node=\"114\">(Q30) Once they’re synchronized, they can just keep on going for much longer periods than they could before.</strong></span></p>\n<p data-path-to-node=\"45\"><strong data-path-to-node=\"45\" data-index-in-node=\"0\">Katie:</strong> Hmm, I can see how that would work. But anyway…</p>"}]', 0);
INSERT INTO public.questions VALUES ('15e8ad4d-4dbf-4ecb-9ab3-b1658215386e', '73d7adee-8d02-40bf-83f2-e8ca2479b9ac', 'matching', 'Questions 27-33', NULL, '<p>Reading Passage 3 has seven paragraphs, <strong>A-G</strong>.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Write the correct number, i-viii, in boxes 27-33 on your answer sheet.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. Hurricanes in history"}, {"optionText": "ii. How hurricanes form"}, {"optionText": "iii. How a laboratory exercise re-route a hurricane"}, {"optionText": "iv. Exciting ways to utilise future technologies"}, {"optionText": "v. Are hurricanes unbeatable?"}, {"optionText": "vi. Re-visit earlier ideas"}, {"optionText": "vii. How lives might have been saved"}, {"optionText": "viii. A range of low-tech methods"}], "matchingItems": null}', 'null', '[{"content": "<h3 data-path-to-node=\"4\">27. Paragraph A</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>v. Are hurricanes unbeatable?</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) Đoạn này mô tả sức mạnh tàn phá khủng khiếp của bão và kết thúc bằng câu hỏi: “<strong>But can we ever find a way to control these formidable forces of nature?</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Câu hỏi cuối cùng tóm tắt ý chính của đoạn: Liệu bão có phải là không thể đánh bại (<em>unbeatable</em>)?</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">28. Paragraph B</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>ii. How hurricanes form</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) Đoạn này giải thích quá trình bão phát triển: từ cụm dông bão (<em>thunderstorm clusters</em>), không khí ẩm nóng bốc lên, sự ngưng tụ (<em>condensation</em>), giải phóng nhiệt, và cuối cùng hình thành mắt bão (<em>eye</em>) và xoáy.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Nội dung đoạn mô tả chi tiết <strong>cách bão hình thành</strong> (<em>How hurricanes form</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">29. Paragraph C</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>vi. Re-visit earlier ideas</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) Tác giả nói rằng các nghiên cứu hiện tại được truyền cảm hứng từ <strong>trực giác trong quá khứ</strong> (<em>past intuition</em>) về lý thuyết hỗn loạn (<em>chaos theory</em>) 30 năm trước. Tác giả có thể <strong>làm mới niềm hứng thú</strong> (<em>renew my enthusiasm</em>) nhờ công nghệ máy tính.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Đoạn này nói về việc <strong>thăm lại những ý tưởng trước đây</strong> (<em>Re-visit earlier ideas</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">30. Paragraph D</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>iii. How a laboratory exercise re-route a hurricane</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) Tác giả mô tả việc sử dụng <strong>thí nghiệm mô phỏng trên máy tính</strong> (<em>simulation experiments on computers</em>) cho bão Iniki và <strong>thành công ngay lập tức</strong> trong việc thay đổi đường đi (<em>altering the path</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Nội dung đoạn mô tả cách một thí nghiệm (trên máy tính/phòng thí nghiệm) đã <strong>chuyển hướng</strong> (<em>re-route</em>) một cơn bão.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">31. Paragraph E</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>vii. How lives might have been saved</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) Đoạn này mô tả sự thay đổi nhỏ trong nhiệt độ và gió đã khiến bão Iniki <strong>“went off the track to the west… leaving Kauai untouched”</strong>.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Việc bão bị lệch hướng và không đổ bộ vào Kauai ngụ ý rằng <strong>sinh mạng có thể đã được cứu</strong> (<em>How lives might have been saved</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"14\">32. Paragraph F</h3>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong>Đáp án:</strong> <strong>iv. Exciting ways to utilise future technologies</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) Đoạn này thảo luận về các <strong>trạm năng lượng mặt trời quay quanh Trái đất trong tương lai</strong> (<em>Future earth-orbiting solar power stations</em>) có thể được điều chỉnh để phát chùm vi sóng làm nóng không khí và thay đổi hướng bão.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong>Giải thích:</strong> Đây là một <strong>cách thức thú vị để tận dụng công nghệ tương lai</strong> (<em>Exciting ways to utilise future technologies</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">33. Paragraph G</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>viii. A range of low-tech methods</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) Đoạn này mô tả các hình thức can thiệp có thể là: “exquisitely targeted <strong>clouds bearing silver iodide</strong> or other rainfall-inducing elements…”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Việc sử dụng các phương pháp tương đối đơn giản như mây mang bạc iodide để thay đổi lượng mưa là một <strong>loạt các phương pháp công nghệ thấp</strong> (<em>A range of low-tech methods</em>).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('9728314b-bc3d-4fa2-ae07-532801d05051', '73d7adee-8d02-40bf-83f2-e8ca2479b9ac', 'fillup', 'Questions 34-38', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 34-38 on your answer sheet.</p>
<p>Hurricanes originate as groups of {thunderstorms} over the tropical oceans. Low-latitude seas continuously provide heat and moisture to the atmosphere, producing warm, humid air above the sea surface. When this air rises, the water vapour in it condenses to form clouds and precipitation. {condensation}  releases heat—the solar heat it took to evaporate the water at the ocean surface. This so-called latent {heat} of condensation makes the air more buoyant, causing it to ascend still higher in a self-reinforcing feedback process. Eventually, the tropical depression begins to organise and strengthen, forming the familiar {eye} —the calm central hub around which a hurricane spins. On passing over {land} , the hurricane’s sustaining source of warm water is cut off, which leads to the storm’s rapid weakening.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"21\">34. Hurricanes originate as groups of <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>thunderstorms</strong> over the tropical oceans.</h3>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong>Đáp án:</strong> <strong>thunderstorms</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “Hurricanes grow in the form of <strong>thunderstorm</strong> clusters above the tropical seas.”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong>Giải thích:</strong> Bão phát triển từ các cụm <strong>dông bão</strong> (<em>thunderstorms</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"23\">35. …the water vapour in it condenses to form clouds and precipitation. <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>Condensation</strong> releases heat…</h3>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong>Đáp án:</strong> <strong>Condensation</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “<strong>Condensation</strong> gives out heat in the process…”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,2,0\"><strong>Giải thích:</strong> Quá trình <strong>ngưng tụ</strong> (<em>Condensation</em>) giải phóng nhiệt.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"25\">36. This so-called latent <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>heat</strong> of condensation makes the air more buoyant…</h3>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong>Đáp án:</strong> <strong>heat</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “This so-called invisible <strong>heat</strong> of condensation makes the air more buoyant…”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong>Giải thích:</strong> Nhiệt (<em>heat</em>) tiềm ẩn của sự ngưng tụ làm cho không khí nổi hơn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"27\">37. …forming the familiar <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>eye</strong> —the calm central hub around which a hurricane spins.</h3>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong>Đáp án:</strong> <strong>eye</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “…forming the familiar <strong>eye</strong> — the calm centre hub that a hurricane spins around.”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong>Giải thích:</strong> Cấu trúc trung tâm được hình thành là <strong>mắt bão</strong> (<em>eye</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"29\">38. On passing over <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>land</strong>, the hurricane’s sustaining source of warm water is cut off…</h3>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong>Đáp án:</strong> <strong>land</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “When reaching the <strong>land</strong>, the hurricane no longer has a continuous supply of warm water, which causes it to swiftly weaken.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong>Giải thích:</strong> Khi đi qua <strong>đất liền</strong> (<em>land</em>), nguồn nước ấm cung cấp cho bão bị cắt đứt.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('ff24d2e9-d82e-48ff-b9a7-6c42728a2446', '9c6bd3a7-4154-4ae7-a079-5cbd103a29d6', 'fillup', 'Questions 7–13', '<p data-path-to-node="4">Complete the notes below.</p>
<p data-path-to-node="4">Choose <strong>ONE WORD ONLY AND/OR A NUMBER</strong> from the passage for each answer. </p>
<h3 style="text-align: center;" data-path-to-node="5">The Project of Arles-Rhône 3</h3>
<p data-path-to-node="6"><strong data-path-to-node="6" data-index-in-node="0">Timeline and Conservation challenges</strong></p>
<ul data-path-to-node="7">
<li>
<p data-path-to-node="7,0,0">The ship had to be taken out of the river by the end of {2011} because of a cultural event in 2013.</p>
</li>
<li>
<p data-path-to-node="7,1,0">The wood was very soft because its cells were full of {water} after 2,000 years.</p>
</li>
<li>
<p data-path-to-node="7,2,0">The team used a special chemical to replace this liquid and then used a freeze-drying method to save the wood.</p>
</li>
</ul>
<p data-path-to-node="8"><strong data-path-to-node="8" data-index-in-node="0">The sinking of the boat</strong></p>
<ul data-path-to-node="9">
<li>
<p data-path-to-node="9,0,0">When the boat sank, it was carrying a heavy load of 33 tons of {stone}</p>
</li>
<li>
<p data-path-to-node="9,1,0">Experts believe a sudden {flood} caused the boat to sink while it was tied at the quay.</p>
</li>
<li>
<p data-path-to-node="9,2,0">Right after the accident, the ship was buried and protected by a thin layer of {clay} .</p>
</li>
</ul>
<p data-path-to-node="10"><strong data-path-to-node="10" data-index-in-node="0">What was found on the boat</strong></p>
<ul data-path-to-node="11">
<li>
<p data-path-to-node="11,0,0">Archaeologists found many personal items such as plates and tools used by the {crew}. .</p>
</li>
<li>
<p data-path-to-node="11,1,0">A silver coin for good luck was also discovered between the wood planks.</p>
</li>
<li>
<p data-path-to-node="11,2,0">Now, the ship is on display in a new part of the local {museum} .</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Câu 7: {2011}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"11\">“That meant the barge needed to be extracted by the end of the diving season in <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"91\">2011</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để kịp cho sự kiện thủ đô văn hóa năm 2013, các nhà khảo cổ có “deadline” phải đưa con tàu lên mặt nước vào cuối mùa lặn năm 2011.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Câu 8: {water}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">“…although the wood of the boat had suffered no microbial decay, <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"78\">water</strong> had filled its cells, leaving the whole structure soft and spongy.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Gỗ không bị mục bởi vi khuẩn nhưng sau 2.000 năm, <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"62\">nước</strong> đã ngấm và lấp đầy các tế bào gỗ, khiến nó trở nên mềm và xốp như bọt biển.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Câu 9: {stone}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“When Arles-Rhône 3 sank, it was carrying 33 tons of <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"64\">stone</strong> for building work.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Con số “33 tons” là dấu hiệu nhận biết (key marker). Vật phẩm mà con tàu đang chở khi bị chìm chính là <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"115\">đá</strong> xây dựng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Câu 10: {flood}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“A flash <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">flood</strong> had probably swamped it.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “swamped” (nhấn chìm/ngập nước) đồng nghĩa với việc gây ra vụ chìm tàu. Nguyên nhân là do một trận <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"114\">lũ</strong> quét đột ngột.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Câu 11: {clay}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“…the barge would have been covered in a coating of fine <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"70\">clay</strong> no more than 20 cm thick.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngay sau khi lũ rút, con tàu bị bao phủ bởi một lớp <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"64\">đất sét</strong> mịn. Lớp màng này đóng vai trò như một “chiếc hộp bảo quản” tự nhiên khỏi oxy và vi khuẩn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Câu 12: {crew}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"11\">“This was where the archaeologists discovered the personal effects that the <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"87\">crew</strong> had left on the boat…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Personal effects” (đồ dùng cá nhân) như bát đĩa, dụng cụ nấu ăn tìm thấy trên tàu được xác định là của <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"116\">thủy thủ đoàn</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Câu 13: {museum}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"11\">“Suddenly nine million euros became available to build a new wing on the <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"84\">museum</strong> and put a Roman barge into it.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi được trục vớt và phục chế, con tàu được đưa vào trưng bày tại một khu vực mới (new wing) của <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"113\">bảo tàng</strong> địa phương.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('92f6c416-8495-469d-a9c8-520c7ef4d4ee', '73d7adee-8d02-40bf-83f2-e8ca2479b9ac', 'radio', 'Questions 39-40', NULL, '<p>Choose the correct letter, A, B, C or D.</p>
<p>Write the correct letter in boxes 39 and 40 on your answer sheet.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A. the huge damage hurricane triggers"}, {"content": "B. the developments in computer technologies"}, {"content": "C. the requirement of some local people"}, {"content": "D. the chaos theory learnt as a student"}], "question": "What encouraged the writer to restart researching hurricane control?"}, {"correct": 2, "options": [{"content": "A. surprised that their intervention had not achieve a lot."}, {"content": "B. ecstatic with the achievement the first experiment had"}, {"content": "C. surprised that their intervention had the intended effect"}, {"content": "D. regretful about the impending success."}], "question": "What was the writer''s reaction after their first experiment?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"34\">39. What encouraged the writer to restart researching hurricane control?</h3>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong>Đáp án:</strong> <strong>B. the developments in computer technologies</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “Back then, I was not able to test my ideas, but thanks to the <strong>advancement of computer simulation and remote-sensing technologies</strong> over the last 10 years, I can now renew my enthusiasm in large-scale weather control.”</p>\n</li>\n<li>\n<p data-path-to-node=\"35,2,0\"><strong>Giải thích:</strong> Sự phát triển của <strong>công nghệ mô phỏng máy tính</strong> (<em>computer simulation technologies</em>) đã cho phép tác giả quay lại nghiên cứu.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"36\">40. What was the writer’s reaction after their first experiment?</h3>\n<ul data-path-to-node=\"37\">\n<li>\n<p data-path-to-node=\"37,0,0\"><strong>Đáp án:</strong> <strong>C. surprised that their intervention had the intended effect</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"37,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “The current forecasting technologies were far from perfect, so <strong>it took us by surprise that our first simulation turned out to be an immediate success</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"37,2,0\"><strong>Giải thích:</strong> Tác giả đã <strong>bất ngờ</strong> (<em>surprised</em>) vì sự can thiệp (<em>intervention</em>) trong mô phỏng (<em>simulation</em>) đã <strong>thành công ngay lập tức</strong> (<em>immediate success</em>), đạt được mục tiêu (<em>intended effect</em>) là thay đổi đường đi của bão.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('fa2514aa-32ba-4675-aabf-b50603174717', '9dc07e7a-357d-4148-a5c9-bebf94577384', 'fillup', 'Questions 6–13', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>LUCY</strong></span></p>
<p><strong>Physical features</strong></p>
<p>– jaws and skull like those of an ape</p>
<p>– braincase similar in size to that of a chimp</p>
<p>– long arms</p>
<p><strong>Movement</strong></p>
<p>– the positioning and shape of her pelvis made it clear that she walked like a human</p>
<p>– upright movement possibility started among the {branches}<span class="fill-history-correct"> </span>of trees</p>
<p>– probably moved to the {ground} in search of food</p>
<p><strong>Diet and eating habits</strong></p>
<p>– analysis of food in the {teeth} of the skeletons of early humans shows changes in their diet</p>
<p>– it is likely that meat and grasses were substituted for {fruit}</p>
<p>– {Eggs } that were located close to Lucy suggest these were also part of her diet</p>
<p>– {Bones} that were found had marks on them, possibly made by tools used for eating</p>
<p><strong>Comparisons with modern-day humans</strong></p>
<p>– modern-day humans have a longer {childhood} than Lucy did</p>
<p>– the {brains }of modern-day humans appear to develop later than Lucy’s did</p>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"1\">Câu 6: branches</h3>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 2-3.</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It may be that upright walking evolved in the trees, as a way to walk along <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"88\">branches</strong>…”</li>\n<li><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đề cập rằng việc đi thẳng có thể đã tiến hóa từ trên cây, như một cách để di chuyển dọc theo các “nhành cây” (branches).</li>\n</ul>\n<h3 data-path-to-node=\"3\">Câu 7: ground</h3>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 4-5.</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “But hunting for food may have been the real reason for heading to the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"82\">ground</strong>…”</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra giả thuyết rằng việc tìm kiếm thức ăn là lý do thực sự khiến loài người cổ đại rời bỏ cây để đi xuống “mặt đất” (ground).</li>\n</ul>\n<h3 data-path-to-node=\"5\">Câu 8: teeth</h3>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 1-2.</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Studies of the remains of food trapped on preserved human <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"70\">teeth</strong> indicate…”</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà khoa học đã phân tích những mảnh vụn thức ăn còn sót lại trên “răng” (teeth) hóa thạch để tìm hiểu về sự thay đổi trong chế độ ăn.</li>\n</ul>\n<h3 data-path-to-node=\"7\">Câu 9: fruit</h3>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 3-4.</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Instead of mostly eating <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"37\">fruit</strong> from trees, they began to include grasses and possibly meat.”</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thay vì chủ yếu ăn “trái cây” (fruit), chế độ ăn của họ đã thay đổi bằng cách bổ sung thêm cỏ và thịt.</li>\n</ul>\n<h3 data-path-to-node=\"9\">Câu 10: eggs</h3>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 5-6.</li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Fossilised crocodile and turtle <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"44\">eggs</strong> were found near her skeleton…”</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tìm thấy hóa thạch “trứng” (eggs) cá sấu và rùa gần bộ xương Lucy gợi ý rằng đây cũng là một phần thức ăn của cô ấy.</li>\n</ul>\n<h3 data-path-to-node=\"11\">Câu 11: bones</h3>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 8, dòng 3-4.</li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…archaeologists uncovered animal <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"47\">bones</strong> with scratches that seem to have been made by stone tools.”</li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những chiếc “xương” (bones) động vật được tìm thấy có các vết trầy xước, cho thấy chúng có thể đã bị tác động bởi các công cụ dùng để ăn thịt.</li>\n</ul>\n<h3 data-path-to-node=\"13\">Câu 12: childhood</h3>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 9, dòng 1-2.</li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It also seems that Lucy’s <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"38\">childhood</strong> was much briefer than ours…”</li>\n<li><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc so sánh và cho biết “tuổi thơ” (childhood) của Lucy ngắn hơn (briefer) so với người hiện đại chúng ta.</li>\n</ul>\n<h3 data-path-to-node=\"15\">Câu 13: brains</h3>\n<ul data-path-to-node=\"16\">\n<li><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 9, dòng 5-6.</li>\n<li><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a recent study of a 3-year-old early human suggested that their <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"79\">brains</strong> matured much earlier than ours do.”</li>\n<li><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu chỉ ra rằng “bộ não” (brains) của loài người cổ đại trưởng thành sớm hơn so với sự phát triển não bộ của người hiện đại.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('52a3ec98-3a80-4cbe-b0b9-5b83a32893c0', '137fc380-8190-44f9-9f39-46893ad74423', 'radio', 'Questions 1 – 7', '', '<p data-path-to-node="6,0,0">Choose<strong data-path-to-node="6,0,0" data-index-in-node="0"> TRUE</strong> if the statement agrees with the information,<strong data-path-to-node="6,1,0" data-index-in-node="0">FALSE</strong> if the statement contradicts the information,<strong data-path-to-node="6,2,0" data-index-in-node="0">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Comprehensive insurance allows a second driver as well as the owner to drive a vehicle."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "You can only drive a friend’s vehicle if you are specifically named on the insurance policy."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Drivers with valid foreign licences are sometimes excluded from insurance policies in the UK."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "When you hire a car, you must obtain valid insurance cover for it yourself."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It is illegal to drive a car in the UK without road tax."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Driving without the necessary insurance always leads to a driving ban."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "You will not be allowed to drive again if you are sent to prison for a driving offence."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. Comprehensive insurance allows a second driver as well as the owner to drive a vehicle. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1 liệt kê 3 loại bảo hiểm: <em data-path-to-node=\"5,0,0\" data-index-in-node=\"43\">Comprehensive; Third Party, Fire and Theft; Third Party only.</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ liệt kê <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"32\">tên</strong> các loại bảo hiểm chứ không hề giải thích chi tiết quyền lợi của gói “Comprehensive” là gì, có cho phép người thứ hai lái hay không. Do đó, thông tin này không có trong bài.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. You can only drive a friend’s vehicle if you are specifically named on the insurance policy. — {FALSE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Some car owners have <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"33\">‘any driver’ insurance</strong> which allows <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"69\">anyone</strong> with a valid driving licence to use their vehicle.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"24\">chỉ khi (only)</strong> được nêu tên cụ thể mới được lái. Tuy nhiên, bài đọc chỉ ra trường hợp ngoại lệ là bảo hiểm “any driver” cho phép bất kỳ ai có bằng lái đều được chạy. Vì có ngoại lệ nên khẳng định “only” là sai.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. Drivers with valid foreign licences are sometimes excluded from insurance policies in the UK. — {TRUE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“…even ‘any driver’ policies <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"42\">may not cover</strong> learner drivers or people driving on <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"93\">foreign licences</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “may not cover” (có thể không bao gồm) tương ứng với “sometimes excluded” (đôi khi bị loại trừ). Điều này xác nhận rằng bằng lái nước ngoài không phải lúc nào cũng được bảo hiểm chấp nhận.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. When you hire a car, you must obtain valid insurance cover for it yourself. — {FALSE}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Insurance and road tax are <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"39\">normally provided by the rental company</strong> and included in the hire charge.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói bạn phải <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"33\">tự mình (yourself)</strong> mua bảo hiểm. Nhưng bài đọc nói công ty cho thuê xe thường đã cung cấp sẵn và tính vào phí thuê rồi.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. It is illegal to drive a car in the UK without road tax. — {TRUE}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…as driving without insurance (or a valid driving licence, or <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"76\">road tax</strong>) is <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"89\">unlawful</strong>…”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Unlawful” đồng nghĩa với “illegal” (bất hợp pháp). Văn bản khẳng định lái xe không có thuế đường bộ (road tax) là phạm luật.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. Driving without the necessary insurance always leads to a driving ban. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“…can lead to you being fined and, <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"48\">on occasion</strong>, banned from driving.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói việc lái xe không bảo hiểm có thể dẫn đến bị phạt tiền và <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"82\">thỉnh thoảng/tùy cơ hội (on occasion)</strong> mới bị cấm lái (banned). Câu hỏi dùng từ <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"161\">always</strong> (luôn luôn) là quá tuyệt đối. Tuy bài đọc nói “on occasion”, nhưng không đủ dữ liệu để nói nó “luôn luôn” hay “không bao giờ”, nên chọn Not Given là an toàn nhất (hoặc False nếu xét tính đối lập giữa ‘thỉnh thoảng’ và ‘luôn luôn’).</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. You will not be allowed to drive again if you are sent to prison for a driving offence. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“Further offences can then result in you being sent to prison.”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói phạm lỗi nặng hơn thì bị <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"53\">đi tù</strong>, nhưng <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"66\">không nói gì</strong> về việc sau khi ra tù người đó có bị cấm lái xe vĩnh viễn hay không.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('b25ec81c-16aa-4f94-96df-5739a8e56988', '137fc380-8190-44f9-9f39-46893ad74423', 'matrix', 'Questions 8 – 14', '', '<p data-path-to-node="13">Write the correct letter, <strong data-path-to-node="13" data-index-in-node="26">A-F</strong>, in boxes 8-14 on your answer sheet.</p>
<p data-path-to-node="14"><strong data-path-to-node="14" data-index-in-node="0">NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "It can be reduced in size between uses, to take up less space.", "correctCategoryLetter": "C"}, {"itemText": "With guidance, children can make it themselves.", "correctCategoryLetter": "E"}, {"itemText": "One item in the pack can be adapted to fit the user.", "correctCategoryLetter": "A"}, {"itemText": "It is designed so that the smaller parts do not fall off.", "correctCategoryLetter": "D"}, {"itemText": "It consists of equipment designed for making one kind of food.", "correctCategoryLetter": "F"}, {"itemText": "It can be used as storage as well as a toy.", "correctCategoryLetter": "C"}, {"itemText": "The materials to decorate it are included in the pack.", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">8. It can be reduced in size between uses, to take up less space. — {C} Castle</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“…can be either <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"29\">folded up and put away</strong>…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc có thể “gấp lại và cất đi” (folded up) chính là hành động thu nhỏ kích thước (reduced in size) để tiết kiệm không gian khi không sử dụng.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">9. With guidance, children can make it themselves. — {E} Bird House</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“…ideal for children to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"37\">construct under supervision</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Construct” đồng nghĩa với “make it themselves”, và “under supervision” (dưới sự giám sát) tương ứng với “with guidance” (có sự hướng dẫn).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">10. One item in the pack can be adapted to fit the user. — {A} Deluxe chef set</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“…apron with <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">adjustable neck strap and waist ties</strong>…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chiếc tạp dề có dây đeo cổ và dây buộc eo “có thể điều chỉnh” (adjustable) chính là để làm cho nó vừa vặn (fit) với người sử dụng.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">11. It is designed so that the smaller parts do not fall off. — {D} Cat and Mouse Game</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“…this compact game is <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"36\">magnetic, so pieces stick to the board – even when on the move</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhờ tính chất “nam châm” (magnetic), các quân cờ sẽ “dính chặt vào bàn” (stick to the board), giúp chúng không bị rơi mất (do not fall off) ngay cả khi đang di chuyển.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">12. It consists of equipment designed for making one kind of food. — {F} Cookie set</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“A baking set for young chefs to make the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"53\">tastiest cookies ever!</strong> … Includes… <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"92\">cookie pan</strong>… and three <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"116\">cookie cutters</strong>.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bộ đồ dùng này (pan, cutters, recipes) chỉ tập trung vào việc làm duy nhất một loại thực phẩm là bánh quy (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"119\">cookies</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">13. It can be used as storage as well as a toy. — {C} Castle</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“…or utilised for <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"31\">keeping other things in</strong> when no-one’s playing with it.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Utilised for keeping other things in” (sử dụng để đựng đồ khác) chính là chức năng lưu trữ (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"105\">storage</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">14. The materials to decorate it are included in the pack. — {E} Bird House</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“Kit contains… as well as <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"39\">brush and paints</strong>.”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc bao gồm sẵn cọ và màu vẽ (brush and paints) trong bộ dụng cụ giúp trẻ có sẵn vật liệu để trang trí (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"117\">decorate</strong>) ngôi nhà chim.</li>\n</ul>"}]', 1);
SET session_replication_role = DEFAULT;
